   1→//! Swarm executor for orchestrating Claude Code swarm execution.
   2→//!
   3→//! The SwarmExecutor is the bridge between Forge and Claude Code swarms. It:
   4→//! - Starts a CallbackServer to receive progress updates
   5→//! - Builds the orchestration prompt using the SwarmContext
   6→//! - Spawns a Claude Code process with the prompt
   7→//! - Monitors execution via HTTP callbacks and stdout
   8→//! - Parses the `<swarm_complete>` signal to determine success/failure
   9→//! - Returns a SwarmResult with execution details
  10→//!
  11→//! ## Usage
  12→//!
  13→//! ```no_run
  14→//! use forge::swarm::{SwarmContext, PhaseInfo, SwarmExecutor, SwarmConfig};
  15→//! use std::path::PathBuf;
  16→//!
  17→//! # async fn example() -> anyhow::Result<()> {
  18→//! let phase = PhaseInfo::new("05", "OAuth Integration", "OAUTH COMPLETE", 20);
  19→//! let config = SwarmConfig::default();
  20→//! let executor = SwarmExecutor::new(config);
  21→//!
  22→//! let context = SwarmContext::new(phase, "", PathBuf::from("/project"));
  23→//! let result = executor.execute(context).await?;
  24→//!
  25→//! if result.success {
  26→//!     println!("Swarm completed successfully!");
  27→//! }
  28→//! # Ok(())
  29→//! # }
  30→//! ```
  31→
  32→use crate::swarm::callback::{CallbackServer, SwarmEvent, TaskComplete, TaskStatus};
  33→use crate::swarm::context::SwarmContext;
  34→use crate::swarm::prompts::{
  35→    SwarmCompletionResult, build_orchestration_prompt, parse_swarm_completion,
  36→};
  37→use anyhow::{Context, Result};
  38→use serde::{Deserialize, Serialize};
  39→use std::path::PathBuf;
  40→use std::process::Stdio;
  41→use std::time::{Duration, Instant};
  42→use tokio::io::{AsyncBufReadExt, AsyncWriteExt, BufReader};
  43→use tokio::process::Command;
  44→use tokio::sync::mpsc;
  45→
  46→/// Default timeout for swarm execution (30 minutes).
  47→const DEFAULT_TIMEOUT_SECS: u64 = 1800;
  48→
  49→/// Default polling interval for checking events (100ms).
  50→const DEFAULT_POLL_INTERVAL_MS: u64 = 100;
  51→
  52→/// Default Claude command.
  53→const DEFAULT_CLAUDE_CMD: &str = "claude";
  54→
  55→/// Configuration for the swarm executor.
  56→#[derive(Debug, Clone)]
  57→pub struct SwarmConfig {
  58→    /// Claude CLI command (default: "claude").
  59→    pub claude_cmd: String,
  60→    /// Working directory for execution.
  61→    pub working_dir: Option<PathBuf>,
  62→    /// Timeout for swarm execution.
  63→    pub timeout: Duration,
  64→    /// Polling interval for event checking.
  65→    pub poll_interval: Duration,
  66→    /// Skip permission prompts in Claude.
  67→    pub skip_permissions: bool,
  68→    /// Verbose output.
  69→    pub verbose: bool,
  70→}
  71→
  72→impl Default for SwarmConfig {
  73→    fn default() -> Self {
  74→        Self {
  75→            claude_cmd: DEFAULT_CLAUDE_CMD.to_string(),
  76→            working_dir: None,
  77→            timeout: Duration::from_secs(DEFAULT_TIMEOUT_SECS),
  78→            poll_interval: Duration::from_millis(DEFAULT_POLL_INTERVAL_MS),
  79→            skip_permissions: true,
  80→            verbose: false,
  81→        }
  82→    }
  83→}
  84→
  85→impl SwarmConfig {
