 201→/// Internal events during swarm execution.
 202→#[derive(Debug)]
 203→enum ExecutionEvent {
 204→    /// Stdout reading completed (all output captured).
 205→    StdoutComplete { output: String },
 206→    /// Callback event received.
 207→    CallbackReceived(SwarmEvent),
 208→    /// Timeout reached.
 209→    Timeout,
 210→}
 211→
 212→/// The swarm executor orchestrates Claude Code swarm execution.
 213→///
 214→/// It manages the lifecycle of a swarm execution:
 215→/// 1. Starting the callback server
 216→/// 2. Building and sending the orchestration prompt
 217→/// 3. Monitoring progress via callbacks and stdout
 218→/// 4. Parsing the completion signal
 219→/// 5. Returning the result
 220→pub struct SwarmExecutor {
 221→    config: SwarmConfig,
 222→}
 223→
 224→impl SwarmExecutor {
 225→    /// Create a new SwarmExecutor with the given configuration.
 226→    pub fn new(config: SwarmConfig) -> Self {
 227→        Self { config }
 228→    }
 229→
 230→    /// Create a SwarmExecutor with default configuration.
 231→    pub fn with_defaults() -> Self {
 232→        Self::new(SwarmConfig::default())
 233→    }
 234→
 235→    /// Execute a swarm for the given context.
 236→    ///
 237→    /// This is the main entry point for swarm execution. It:
 238→    /// 1. Starts the callback server
 239→    /// 2. Builds the orchestration prompt
 240→    /// 3. Spawns Claude Code with the prompt
 241→    /// 4. Monitors execution until completion or timeout
 242→    /// 5. Returns the result
 243→    ///
 244→    /// # Errors
 245→    ///
 246→    /// Returns an error if:
 247→    /// - The callback server fails to start
 248→    /// - The Claude process fails to spawn
 249→    /// - The execution times out
 250→    pub async fn execute(&self, mut context: SwarmContext) -> Result<SwarmResult> {
 251→        let start = Instant::now();
 252→        let phase_number = context.phase.number.clone();
 253→
 254→        // 1. Start callback server
 255→        let mut callback_server = CallbackServer::new();
 256→        let callback_url = callback_server
 257→            .start()
 258→            .await
 259→            .context("Failed to start callback server")?;
 260→
 261→        if self.config.verbose {
 262→            eprintln!("[swarm] Callback server started at {}", callback_url);
 263→        }
 264→
 265→        // Update context with actual callback URL
 266→        context.callback_url = callback_url.clone();
 267→
 268→        // 2. Build orchestration prompt
 269→        let prompt = build_orchestration_prompt(&context);
 270→
 271→        if self.config.verbose {
 272→            eprintln!("[swarm] Generated prompt ({} chars)", prompt.len());
 273→        }
 274→
 275→        // 3. Determine working directory
 276→        let working_dir = self
 277→            .config
 278→            .working_dir
 279→            .clone()
 280→            .unwrap_or_else(|| context.working_dir.clone());
 281→
 282→        // 4. Spawn Claude process and monitor execution
 283→        let result = self
 284→            .run_claude_process(&prompt, &working_dir, &mut callback_server, start)
 285→            .await;
 286→
 287→        // 5. Cleanup callback server
 288→        if let Err(e) = callback_server.stop().await {
 289→            eprintln!("[swarm] Warning: Failed to stop callback server: {}", e);
 290→        }
 291→
 292→        // Return result with phase info
 293→        match result {
 294→            Ok(mut res) => {
 295→                res.phase = phase_number;
 296→                Ok(res)
 297→            }
 298→            Err(e) => {
 299→                let duration = start.elapsed();
 300→                Ok(SwarmResult::failure(
 301→                    phase_number,
 302→                    e.to_string(),
 303→                    Vec::new(),
 304→                    Vec::new(),
 305→                    duration,
 306→                    0,
 307→                    -1,
 308→                ))
 309→            }
 310→        }
 311→    }
 312→
 313→    /// Run the Claude process and monitor its execution.
 314→    async fn run_claude_process(
 315→        &self,
 316→        prompt: &str,
 317→        working_dir: &PathBuf,
 318→        callback_server: &mut CallbackServer,
 319→        start: Instant,
 320→    ) -> Result<SwarmResult> {
 321→        // Build command
 322→        let mut cmd = Command::new(&self.config.claude_cmd);
 323→        cmd.arg("--print");
 324→        cmd.arg("--output-format").arg("stream-json");
 325→
 326→        if self.config.skip_permissions {
 327→            cmd.arg("--dangerously-skip-permissions");
 328→        }
 329→
 330→        // Note: stderr is set to inherit so Claude errors are visible in terminal.
 331→        // Using piped() without reading could cause the process to block if buffer fills.
 332→        cmd.current_dir(working_dir)
 333→            .stdin(Stdio::piped())
 334→            .stdout(Stdio::piped())
 335→            .stderr(Stdio::inherit());
 336→
 337→        if self.config.verbose {
 338→            eprintln!("[swarm] Spawning Claude process in {:?}", working_dir);
 339→        }
 340→
 341→        // Spawn process
 342→        let mut child = cmd.spawn().context("Failed to spawn Claude process")?;
 343→
 344→        let child_pid = child.id().unwrap_or(0);
 345→        if self.config.verbose {
 346→            eprintln!("[swarm] Process spawned (PID: {})", child_pid);
 347→        }
 348→
 349→        // Write prompt to stdin
 350→        if let Some(mut stdin) = child.stdin.take() {
 351→            stdin
 352→                .write_all(prompt.as_bytes())
 353→                .await
 354→                .context("Failed to write prompt to stdin")?;
 355→            stdin.shutdown().await.context("Failed to close stdin")?;
 356→        }
 357→
 358→        // Set up stdout reader
 359→        let stdout = child.stdout.take().context("Failed to get stdout")?;
 360→        let reader = BufReader::new(stdout);
 361→
 362→        // Create channels for coordinating events
 363→        let (event_tx, mut event_rx) = mpsc::channel::<ExecutionEvent>(100);
 364→
 365→        // Spawn task to read stdout
 366→        let stdout_tx = event_tx.clone();
 367→        let verbose = self.config.verbose;
 368→        let stdout_task =
 369→            tokio::spawn(async move { Self::read_stdout(reader, stdout_tx, verbose).await });
 370→
 371→        // Spawn task to poll callback events
 372→        let callback_tx = event_tx.clone();
 373→        let poll_interval = self.config.poll_interval;
 374→        let callback_state = callback_server.state_clone();
 375→        let callback_task = tokio::spawn(async move {
 376→            Self::poll_callbacks(callback_state, callback_tx, poll_interval).await
 377→        });
 378→
 379→        // Spawn timeout task
 380→        let timeout = self.config.timeout;
 381→        let timeout_tx = event_tx;
 382→        let timeout_task = tokio::spawn(async move {
 383→            tokio::time::sleep(timeout).await;
 384→            let _ = timeout_tx.send(ExecutionEvent::Timeout).await;
 385→        });
 386→
 387→        // Collect results
 388→        let mut accumulated_output = String::new();
 389→        let mut callback_events: Vec<SwarmEvent> = Vec::new();
 390→        let mut exit_code = -1;
 391→        let mut timed_out = false;
 392→        let mut stdout_complete = false;
 393→        let mut process_exited = false;
 394→
 395→        // Wait for both stdout to close AND process to exit (or timeout)
 396→        loop {
 397→            tokio::select! {
 398→                // Check for events from our monitoring tasks
 399→                Some(event) = event_rx.recv() => {
 400→                    match event {
 401→                        ExecutionEvent::StdoutComplete { output } => {
 402→                            accumulated_output = output;
 403→                            stdout_complete = true;
 404→                            // If process already exited, we're done
 405→                            if process_exited {
 406→                                break;
 407→                            }
 408→                        }
 409→                        ExecutionEvent::CallbackReceived(cb_event) => {
 410→                            callback_events.push(cb_event);
 411→                        }
 412→                        ExecutionEvent::Timeout => {
 413→                            timed_out = true;
 414→                            // Kill the process
 415→                            let _ = child.kill().await;
 416→                            break;
 417→                        }
 418→                    }
 419→                }
 420→                // Wait for the process to exit
 421→                result = child.wait(), if !process_exited => {
 422→                    match result {
 423→                        Ok(status) => {
 424→                            exit_code = status.code().unwrap_or(-1);
 425→                            process_exited = true;
 426→                            // If stdout already complete, we're done
 427→                            if stdout_complete {
 428→                                break;
 429→                            }
 430→                        }
 431→                        Err(e) => {
 432→                            eprintln!("[swarm] Warning: Error waiting for process: {}", e);
 433→                            process_exited = true;
 434→                            if stdout_complete {
 435→                                break;
 436→                            }
 437→                        }
 438→                    }
 439→                }
 440→            }
 441→        }
 442→
 443→        // Abort monitoring tasks
 444→        stdout_task.abort();
 445→        callback_task.abort();
 446→        timeout_task.abort();
 447→
 448→        // Get any remaining callback events
 449→        let remaining_events = callback_server.drain_events().await;
 450→        callback_events.extend(remaining_events);
 451→
 452→        let duration = start.elapsed();
 453→        let progress_events = callback_events.len();
 454→
 455→        if self.config.verbose {
 456→            eprintln!(
 457→                "[swarm] Execution completed in {:?} (exit: {}, events: {})",
 458→                duration, exit_code, progress_events
 459→            );
 460→        }
 461→
 462→        // Handle timeout
 463→        if timed_out {
 464→            return Ok(SwarmResult::failure(
 465→                String::new(),
 466→                format!("Swarm execution timed out after {:?}", self.config.timeout),
 467→                extract_completed_tasks(&callback_events),
 468→                Vec::new(),
 469→                duration,
 470→                progress_events,
 471→                exit_code,
 472→            ));
 473→        }
 474→
 475→        // Parse completion signal from output
 476→        if let Some(completion) = parse_swarm_completion(&accumulated_output) {
 477→            return Ok(self.build_result_from_completion(
 478→                completion,
 479→                duration,
 480→                progress_events,
 481→                exit_code,
 482→            ));
 483→        }
 484→
 485→        // No completion signal found - check if we have callback data
 486→        let tasks_completed = extract_completed_tasks(&callback_events);
 487→        let files_changed = extract_files_changed(&callback_events);
 488→
 489→        if exit_code == 0 && !tasks_completed.is_empty() {
 490→            // Process exited successfully and we have completed tasks
 491→            Ok(SwarmResult::success(
 492→                String::new(),
 493→                tasks_completed,
 494→                files_changed,
 495→                Vec::new(),
 496→                duration,
 497→                progress_events,
 498→                exit_code,
 499→            ))
 500→        } else if exit_code == 0 {
 501→            // Process exited successfully but no completion signal
 502→            Ok(SwarmResult::failure(
 503→                String::new(),
 504→                "No completion signal received from swarm".to_string(),
 505→                tasks_completed,
 506→                Vec::new(),
 507→                duration,
 508→                progress_events,
 509→                exit_code,
 510→            ))
 511→        } else {
 512→            // Process failed
 513→            Ok(SwarmResult::failure(
 514→                String::new(),
 515→                format!("Claude process exited with code {}", exit_code),
 516→                tasks_completed,
 517→                Vec::new(),
 518→                duration,
 519→                progress_events,
 520→                exit_code,
 521→            ))
 522→        }
 523→    }
