 525→    /// Read stdout from the Claude process.
 526→    async fn read_stdout(
 527→        reader: BufReader<tokio::process::ChildStdout>,
 528→        tx: mpsc::Sender<ExecutionEvent>,
 529→        verbose: bool,
 530→    ) {
 531→        let mut lines = reader.lines();
 532→        let mut accumulated = String::new();
 533→
 534→        while let Ok(Some(line)) = lines.next_line().await {
 535→            if verbose
 536→                && !line.is_empty()
 537→                && let Ok(json) = serde_json::from_str::<serde_json::Value>(&line)
 538→                && let Some(msg_type) = json.get("type").and_then(|t| t.as_str())
 539→            {
 540→                eprintln!("[swarm] Event: {}", msg_type);
 541→            }
 542→            accumulated.push_str(&line);
 543→            accumulated.push('\n');
 544→        }
 545→
 546→        let _ = tx
 547→            .send(ExecutionEvent::StdoutComplete {
 548→                output: accumulated,
 549→            })
 550→            .await;
 551→    }
 552→
 553→    /// Poll the callback server for events.
 554→    async fn poll_callbacks(
 555→        state: std::sync::Arc<tokio::sync::RwLock<super::callback::ServerState>>,
 556→        tx: mpsc::Sender<ExecutionEvent>,
 557→        interval: Duration,
 558→    ) {
 559→        let mut ticker = tokio::time::interval(interval);
 560→        let mut last_count = 0;
 561→
 562→        loop {
 563→            ticker.tick().await;
 564→
 565→            let events = {
 566→                let state = state.read().await;
 567→                if state.events.len() > last_count {
 568→                    let new_events: Vec<_> =
 569→                        state.events.iter().skip(last_count).cloned().collect();
 570→                    last_count = state.events.len();
 571→                    new_events
 572→                } else {
 573→                    Vec::new()
 574→                }
 575→            };
 576→
 577→            for event in events {
 578→                if tx
 579→                    .send(ExecutionEvent::CallbackReceived(event))
 580→                    .await
 581→                    .is_err()
 582→                {
 583→                    return;
 584→                }
 585→            }
 586→        }
 587→    }
 588→
 589→    /// Build a SwarmResult from a parsed completion signal.
 590→    fn build_result_from_completion(
 591→        &self,
 592→        completion: SwarmCompletionResult,
 593→        duration: Duration,
 594→        progress_events: usize,
 595→        exit_code: i32,
 596→    ) -> SwarmResult {
 597→        let reviews = completion
 598→            .reviews
 599→            .into_iter()
 600→            .map(|r| ReviewOutcome {
 601→                specialist: r.specialist,
 602→                verdict: r.verdict,
 603→            })
 604→            .collect();
 605→
 606→        if completion.success {
 607→            SwarmResult::success(
 608→                completion.phase,
 609→                completion.tasks_completed,
 610→                completion.files_changed,
 611→                reviews,
 612→                duration,
 613→                progress_events,
 614→                exit_code,
 615→            )
 616→        } else {
 617→            SwarmResult {
 618→                success: false,
 619→                phase: completion.phase,
 620→                tasks_completed: completion.tasks_completed,
 621→                tasks_failed: completion.tasks_failed,
 622→                reviews,
 623→                files_changed: completion.files_changed,
 624→                error: completion.error,
 625→                duration,
 626→                progress_events,
 627→                exit_code,
 628→            }
 629→        }
 630→    }
 631→}
 632→
 633→/// Extract completed task IDs from callback events.
 634→fn extract_completed_tasks(events: &[SwarmEvent]) -> Vec<String> {
 635→    events
 636→        .iter()
 637→        .filter_map(|e| {
 638→            if let SwarmEvent::Complete(TaskComplete {
 639→                task,
 640→                status: TaskStatus::Success,
 641→                ..
 642→            }) = e
 643→            {
 644→                Some(task.clone())
 645→            } else {
 646→                None
 647→            }
 648→        })
 649→        .collect()
 650→}
 651→
 652→/// Extract files changed from callback events.
 653→fn extract_files_changed(events: &[SwarmEvent]) -> Vec<String> {
 654→    let mut files: Vec<String> = events
 655→        .iter()
 656→        .filter_map(|e| {
 657→            if let SwarmEvent::Complete(TaskComplete { files_changed, .. }) = e {
 658→                Some(files_changed.clone())
 659→            } else {
 660→                None
 661→            }
 662→        })
 663→        .flatten()
 664→        .collect();
 665→
 666→    files.sort();
 667→    files.dedup();
 668→    files
 669→}
