  1→/** Expandable agent run card — collapsed summary with status, expanded tabbed detail view. */
  2→import { useState, useEffect, useRef } from 'react';
  3→import type { AgentRunCard as AgentRunCardType, PipelinePhase, AgentTeamDetail, AgentEvent, PipelineStatus, AgentEventType, PipelineOutputEvent, PipelineFileChange } from '../types';
