 57→/** AgentRunCard displays a pipeline run as a collapsible card with output, phases, and files tabs. */
 58→export default function AgentRunCard({
 59→  card,
 60→  phases,
 61→  agentTeam,
 62→  agentEvents,
 63→  pipelineEvents,
 64→  pipelineOutputEvents,
 65→  pipelineFileChanges,
 66→  onCancel,
 67→  viewMode: _viewMode,
 68→}: AgentRunCardProps): React.JSX.Element {
 69→  const { run, issue, project } = card;
 70→  const [expanded, setExpanded] = useState(false);
 71→  const [activeTab, setActiveTab] = useState<DetailTab>('output');
 72→  const [elapsed, setElapsed] = useState('');
 73→  const outputRef = useRef<HTMLDivElement>(null);
 74→
 75→  // Live elapsed timer
 76→  useEffect(() => {
 77→    if (run.status !== 'running' && run.status !== 'queued') {
 78→      if (run.started_at && run.completed_at) {
 79→        const diff = new Date(run.completed_at).getTime() - new Date(run.started_at).getTime();
 80→        const m = Math.floor(diff / 60000);
 81→        const s = Math.floor((diff % 60000) / 1000);
 82→        setElapsed(`${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`);
 83→      }
 84→      return;
 85→    }
 86→
 87→    const start = new Date(run.started_at).getTime();
 88→    const tick = () => {
 89→      const diff = Date.now() - start;
 90→      const m = Math.floor(diff / 60000);
 91→      const s = Math.floor((diff % 60000) / 1000);
 92→      setElapsed(`${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`);
 93→    };
 94→    tick();
 95→    const interval = setInterval(tick, 1000);
 96→    return () => clearInterval(interval);
 97→  }, [run.status, run.started_at, run.completed_at]);
 98→
 99→  // Auto-scroll output
100→  useEffect(() => {
101→    if (expanded && activeTab === 'output' && outputRef.current) {
102→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
103→    }
104→  });
105→
106→  // Collect all events for this run — from agent team tasks and/or pipeline-level output
107→  const allEvents: AgentEvent[] = [];
108→  if (agentTeam && agentEvents) {
109→    for (const task of agentTeam.tasks) {
110→      const events = agentEvents.get(task.id) ?? [];
111→      allEvents.push(...events);
112→    }
113→  }
114→  if (pipelineEvents && pipelineEvents.length > 0) {
115→    allEvents.push(...pipelineEvents);
116→  }
117→  if (allEvents.length > 1) {
118→    allEvents.sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime());
119→  }
120→
121→  const progress = run.phase_count
122→    ? Math.round(((run.current_phase ?? 0) / run.phase_count) * 100)
123→    : 0;
124→
125→  return (
126→    <div
127→      data-testid="agent-run-card"
128→      onClick={() => setExpanded(!expanded)}
129→      style={{
130→        backgroundColor: 'var(--color-bg-card)',
131→        border: '1px solid var(--color-border)',
132→        borderLeft: `3px solid ${STATUS_DOT_COLORS[run.status] ?? 'var(--color-border)'}`,
133→        cursor: 'pointer',
134→        transition: 'background-color 0.15s',
135→      }}
136→      onMouseEnter={e => (e.currentTarget.style.backgroundColor = 'var(--color-bg-card-hover)')}
137→      onMouseLeave={e => (e.currentTarget.style.backgroundColor = 'var(--color-bg-card)')}
138→    >
139→      {/* Collapsed view */}
140→      <div style={{
141→        display: 'flex',
142→        alignItems: 'center',
143→        padding: '12px',
144→        gap: '12px',
145→      }}>
146→        {/* Status dot */}
147→        <span
148→          data-testid="status-dot"
149→          className={run.status === 'running' ? 'pulse-dot' : undefined}
150→          style={{
151→            width: '8px',
152→            height: '8px',
153→            borderRadius: '50%',
154→            backgroundColor: STATUS_DOT_COLORS[run.status],
155→            flexShrink: 0,
156→          }}
157→        />
158→
159→        {/* Project badge + title */}
160→        <div style={{ flex: 1, minWidth: 0 }}>
161→          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
162→            <span style={{
163→              fontSize: '10px',
164→              padding: '1px 6px',
165→              backgroundColor: 'var(--color-border)',
166→              color: 'var(--color-text-secondary)',
167→              textTransform: 'uppercase',
168→              letterSpacing: '0.5px',
169→              flexShrink: 0,
170→            }}>
171→              {project.name}
172→            </span>
173→            <span style={{
174→              overflow: 'hidden',
175→              textOverflow: 'ellipsis',
176→              whiteSpace: 'nowrap',
177→              fontSize: '13px',
178→            }}>
179→              {issue.title}
180→            </span>
181→          </div>
182→        </div>
183→
184→        {/* Phase dots */}
185→        {run.phase_count && (
186→          <div style={{ display: 'flex', gap: '3px', flexShrink: 0 }}>
187→            {Array.from({ length: run.phase_count }, (_, i) => {
188→              const phaseNum = i + 1;
189→              const isCurrent = phaseNum === (run.current_phase ?? 0);
190→              const isDone = phaseNum < (run.current_phase ?? 0);
191→              return (
192→                <span
193→                  key={i}
194→                  data-testid="phase-dot"
195→                  className={isCurrent && run.status === 'running' ? 'pulse-dot' : undefined}
196→                  style={{
197→                    width: '6px',
198→                    height: '6px',
199→                    borderRadius: '50%',
200→                    backgroundColor: isDone
201→                      ? 'var(--color-success)'
202→                      : isCurrent
203→                        ? 'var(--color-info)'
204→                        : 'var(--color-border)',
205→                  }}
206→                />
207→              );
208→            })}
209→          </div>
210→        )}
211→
212→        {/* Status label */}
213→        <span style={{
214→          fontSize: '11px',
215→          color: STATUS_DOT_COLORS[run.status],
216→          fontWeight: 600,
217→          flexShrink: 0,
218→          width: '60px',
219→          textAlign: 'right',
220→        }}>
221→          {STATUS_LABELS[run.status]}
222→        </span>
223→
224→        {/* Elapsed */}
225→        <span style={{
226→          fontSize: '12px',
227→          color: 'var(--color-text-secondary)',
228→          flexShrink: 0,
229→          width: '50px',
230→          textAlign: 'right',
231→          fontVariantNumeric: 'tabular-nums',
232→        }}>
233→          {elapsed}
234→        </span>
235→
236→        {/* Expand chevron */}
237→        <span style={{
238→          color: 'var(--color-text-secondary)',
239→          transform: expanded ? 'rotate(180deg)' : 'rotate(0deg)',
240→          transition: 'transform 0.2s',
241→          flexShrink: 0,
242→        }}>
243→          &#x25BC;
244→        </span>
245→      </div>
246→
247→      {/* Progress bar */}
248→      {run.status === 'running' && (
249→        <div style={{
250→          height: '2px',
251→          backgroundColor: 'var(--color-border)',
252→        }}>
253→          <div
254→            data-testid="progress-bar"
255→            style={{
256→              height: '100%',
257→              width: `${progress}%`,
258→              backgroundColor: 'var(--color-success)',
259→              transition: 'width 0.3s',
260→            }}
261→          />
262→        </div>
263→      )}
264→
265→      {/* Expanded detail view */}
266→      {expanded && (
267→        <div
268→          onClick={e => e.stopPropagation()}
269→          style={{ borderTop: '1px solid var(--color-border)' }}
270→        >
271→          {/* Tabs */}
272→          <div style={{
273→            display: 'flex',
274→            borderBottom: '1px solid var(--color-border)',
275→          }}>
276→            {(['output', 'phases', 'files'] as DetailTab[]).map(tab => (
277→              <button
278→                key={tab}
279→                onClick={() => setActiveTab(tab)}
280→                style={{
281→                  padding: '8px 16px',
282→                  background: 'transparent',
283→                  border: 'none',
284→                  borderBottom: activeTab === tab ? '2px solid var(--color-success)' : '2px solid transparent',
285→                  color: activeTab === tab ? 'var(--color-text-primary)' : 'var(--color-text-secondary)',
286→                  cursor: 'pointer',
287→                  fontSize: '12px',
288→                  fontFamily: 'inherit',
289→                  textTransform: 'uppercase',
290→                  letterSpacing: '0.5px',
291→                }}
292→              >
293→                {tab}
294→              </button>
295→            ))}
296→
297→            {/* Cancel button for running pipelines */}
298→            {run.status === 'running' && onCancel && (
299→              <button
300→                onClick={() => onCancel(run.id)}
301→                style={{
302→                  marginLeft: 'auto',
303→                  padding: '8px 16px',
304→                  background: 'transparent',
305→                  border: 'none',
306→                  color: 'var(--color-error)',
307→                  cursor: 'pointer',
308→                  fontSize: '12px',
309→                  fontFamily: 'inherit',
310→                }}
311→              >
312→                cancel
313→              </button>
314→            )}
315→          </div>
316→
317→          {/* Tab content */}
318→          <div style={{ padding: '12px', maxHeight: '400px', overflow: 'hidden' }}>
319→            {activeTab === 'output' && (
320→              <div
321→                ref={outputRef}
322→                style={{
323→                  backgroundColor: '#000',
324→                  padding: '12px',
325→                  maxHeight: '376px',
326→                  overflowY: 'auto',
327→                  fontSize: '12px',
328→                  lineHeight: '1.6',
329→                }}
330→              >
331→                {pipelineOutputEvents && pipelineOutputEvents.length > 0 ? (
332→                  pipelineOutputEvents.map((evt, i) => {
333→                    if (evt.content_type === 'text') {
334→                      return (
335→                        <div key={i} style={{ color: 'var(--color-text-primary)', whiteSpace: 'pre-wrap' }}>
336→                          {evt.content}
337→                        </div>
338→                      );
339→                    }
340→                    if (evt.content_type === 'tool_start') {
341→                      return (
342→                        <div key={i} style={{ color: '#39d353', padding: '2px 0' }}>
343→                          <span style={{
344→                            display: 'inline-block',
345→                            padding: '1px 6px',
346→                            backgroundColor: 'rgba(57, 211, 83, 0.15)',
347→                            marginRight: '8px',
348→                            fontSize: '11px',
349→                          }}>
350→                            {evt.content}
351→                          </span>
352→                          <span style={{ color: 'var(--color-text-secondary)' }}>
353→                            {evt.input_summary}
354→                          </span>
355→                        </div>
356→                      );
357→                    }
358→                    if (evt.content_type === 'thinking') {
359→                      return (
360→                        <div key={i} style={{
361→                          color: 'var(--color-text-secondary)',
362→                          fontStyle: 'italic',
363→                          borderLeft: '2px solid var(--color-border)',
364→                          paddingLeft: '8px',
365→                          opacity: 0.7,
366→                        }}>
367→                          {evt.content}
368→                        </div>
369→                      );
