379→                  allEvents.map((event, i) => (
380→                    <div key={i} style={{ color: EVENT_TYPE_COLORS[event.event_type] ?? 'var(--color-text-primary)' }}>
381→                      <span style={{ color: 'var(--color-text-secondary)', marginRight: '8px' }}>
382→                        [{event.event_type}]
383→                      </span>
384→                      {event.content}
385→                    </div>
386→                  ))
387→                )}
388→              </div>
389→            )}
390→
391→            {activeTab === 'phases' && (
392→              <div style={{ fontSize: '13px' }}>
393→                {(phases ?? []).length === 0 ? (
394→                  <span style={{ color: 'var(--color-text-secondary)' }}>No phases yet...</span>
395→                ) : (
396→                  (phases ?? []).map((phase, i) => (
397→                    <div key={i} style={{
398→                      display: 'flex',
399→                      alignItems: 'center',
400→                      gap: '12px',
401→                      padding: '6px 0',
402→                      borderBottom: '1px solid var(--color-border)',
