412→                      }}>
413→                        {phase.status === 'completed' ? '\u2713' : phase.status === 'running' ? '\u25B6' : '\u25CB'}
414→                      </span>
415→                      <span style={{ flex: 1 }}>{phase.phase_name}</span>
416→                      {phase.iteration != null && phase.budget != null && (
417→                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
