425→                          backgroundColor: phase.review_status === 'passed'
426→                            ? 'var(--color-success)'
427→                            : 'var(--color-warning)',
428→                          color: '#000',
429→                        }}>
430→                          {phase.review_status}
431→                        </span>
432→                      )}
433→                    </div>
434→                  ))
435→                )}
436→              </div>
437→            )}
438→
439→            {activeTab === 'files' && (
440→              <div style={{ fontSize: '13px', color: 'var(--color-text-secondary)' }}>
441→                {run.branch_name ? (
442→                  <div style={{ marginBottom: '8px' }}>
443→                    <span style={{ color: 'var(--color-text-secondary)' }}>branch: </span>
444→                    <span style={{ color: 'var(--color-info)' }}>{run.branch_name}</span>
445→                  </div>
446→                ) : null}
447→                {run.pr_url ? (
448→                  <div style={{ marginBottom: '8px' }}>
449→                    <span style={{ color: 'var(--color-text-secondary)' }}>PR: </span>
