470→                        <div key={i} style={{
471→                          display: 'flex',
472→                          alignItems: 'center',
473→                          gap: '8px',
474→                          padding: '2px 0',
475→                          fontFamily: 'monospace',
476→                          fontSize: '12px',
477→                        }}>
478→                          <span style={{
