482→                            width: '12px',
483→                            textAlign: 'center',
484→                          }}>
485→                            {fc.action === 'created' ? '+' : fc.action === 'modified' ? '~' : '-'}
486→                          </span>
487→                          <span style={{ color: 'var(--color-text-primary)' }}>
488→                            {fc.file_path}
489→                          </span>
490→                        </div>
491→                      ));
492→                    })()}
493→                  </div>
494→                ) : !run.branch_name && !run.pr_url ? (
495→                  <span>No file changes yet...</span>
496→                ) : null}
497→              </div>
498→            )}
499→          </div>
500→        </div>
501→      )}
502→    </div>
503→  );
504→}
