  1→/** Unified state hook for the Mission Control dashboard — aggregates all projects into a single view. */
  2→import { useState, useEffect, useCallback, useRef, useMemo } from 'react';
  3→import { api } from '../api/client';
  4→import { useWsSubscribe } from '../contexts/WebSocketContext';
  5→import type {
  6→  Project,
  7→  Issue,
  8→  PipelineRun,
  9→  PipelinePhase,
 10→  AgentRunCard,
 11→  EventLogEntry,
 12→  WsMessage,
 13→  RunStatusFilter,
 14→  AgentTeamDetail,
 15→  AgentEvent,
 16→  PipelineOutputEvent,
 17→  PipelineFileChange,
 18→} from '../types';
 19→
 20→/** Internal state shape for the Mission Control hook */
 21→interface MissionControlState {
 22→  projects: Project[];
 23→  runs: Map<number, PipelineRun>;
 24→  issues: Map<number, Issue>;
 25→  phases: Map<number, PipelinePhase[]>;
 26→  agentTeams: Map<number, AgentTeamDetail>;
 27→  agentEvents: Map<number, AgentEvent[]>;
 28→  pipelineEvents: Map<number, AgentEvent[]>;
 29→  pipelineOutputEvents: Map<number, PipelineOutputEvent[]>;
 30→  pipelineFileChanges: Map<number, PipelineFileChange[]>;
 31→  eventLog: EventLogEntry[];
 32→  loading: boolean;
 33→  error: string | null;
 34→}
 35→
 36→/** An idle issue card — issue without an active pipeline run */
 37→export interface IdleIssueCard {
 38→  issue: Issue;
 39→  project: Project;
 40→}
 41→
 42→/** Return type of the useMissionControl hook */
 43→export interface MissionControlReturn {
 44→  /** All loaded projects */
 45→  projects: Project[];
 46→  /** Filtered and sorted agent run cards for the grid */
 47→  agentRunCards: AgentRunCard[];
 48→  /** Issues without active pipeline runs, available to start */
 49→  idleIssueCards: IdleIssueCard[];
 50→  /** Run counts by status */
 51→  statusCounts: Record<RunStatusFilter, number>;
 52→  /** Chronological event log entries */
 53→  eventLog: EventLogEntry[];
 54→  /** Pipeline phases by run ID */
 55→  phases: Map<number, PipelinePhase[]>;
 56→  /** Agent team details by run ID */
 57→  agentTeams: Map<number, AgentTeamDetail>;
 58→  /** Agent events by task ID */
 59→  agentEvents: Map<number, AgentEvent[]>;
 60→  /** Pipeline-level output events by run ID (for forge fallback path) */
 61→  pipelineEvents: Map<number, AgentEvent[]>;
 62→  /** Rich pipeline output events by run ID */
 63→  pipelineOutputEvents: Map<number, PipelineOutputEvent[]>;
 64→  /** File changes by run ID */
 65→  pipelineFileChanges: Map<number, PipelineFileChange[]>;
 66→  /** Whether initial data is still loading */
 67→  loading: boolean;
 68→  /** Error message from initial load, or null */
 69→  error: string | null;
 70→  /** Currently selected project ID filter, or null for all */
 71→  selectedProjectId: number | null;
 72→  /** Set the project filter */
 73→  setSelectedProjectId: (id: number | null) => void;
 74→  /** Current status filter */
 75→  statusFilter: RunStatusFilter;
 76→  /** Set the status filter */
 77→  setStatusFilter: (filter: RunStatusFilter) => void;
 78→  /** Trigger a pipeline run for an issue */
 79→  triggerPipeline: (issueId: number) => Promise<void>;
 80→  /** Cancel a running pipeline */
 81→  cancelPipeline: (runId: number) => Promise<void>;
 82→  /** Create a new issue in a project */
 83→  createIssue: (projectId: number, title: string, description: string) => Promise<Issue>;
 84→  /** Create a new project */
 85→  createProject: (name: string, path: string) => Promise<Project>;
 86→  /** Clone a project from a repository URL */
 87→  cloneProject: (repoUrl: string) => Promise<Project>;
 88→  /** Delete a project and all its data */
 89→  deleteProject: (projectId: number) => Promise<void>;
 90→  /** Refresh all data from the server */
 91→  refresh: () => Promise<void>;
 92→  /** Issue counts grouped by project ID */
 93→  issuesByProject: Map<number, number>;
 94→}
 95→
 96→/** Status sort order: running first, then queued, failed, completed, cancelled */
 97→const STATUS_ORDER: Record<string, number> = {
 98→  running: 0,
 99→  queued: 1,
100→  failed: 2,
101→  completed: 3,
102→  cancelled: 4,
103→};
104→
105→/**
106→ * Primary data hook for the Mission Control dashboard.
107→ * Aggregates data from all projects, handles WebSocket updates,
108→ * and provides filtering and actions.
109→ */
110→export default function useMissionControl(): MissionControlReturn {
111→  const [state, setState] = useState<MissionControlState>({
112→    projects: [],
113→    runs: new Map(),
114→    issues: new Map(),
115→    phases: new Map(),
116→    agentTeams: new Map(),
117→    agentEvents: new Map(),
118→    pipelineEvents: new Map(),
119→    pipelineOutputEvents: new Map(),
120→    pipelineFileChanges: new Map(),
121→    eventLog: [],
122→    loading: true,
123→    error: null,
124→  });
125→
126→  const [selectedProjectId, setSelectedProjectId] = useState<number | null>(null);
127→  const [statusFilter, setStatusFilter] = useState<RunStatusFilter>('all');
128→  const eventIdRef = useRef(0);
129→  const mountedRef = useRef(true);
130→
131→  /** Add an event log entry, capping at 500 entries */
132→  const addLogEntry = useCallback((
133→    source: EventLogEntry['source'],
134→    message: string,
135→    projectName?: string,
136→    runId?: number,
137→  ) => {
138→    setState(prev => ({
139→      ...prev,
140→      eventLog: [
141→        ...prev.eventLog.slice(-499),
142→        {
143→          id: String(++eventIdRef.current),
144→          timestamp: new Date().toISOString(),
145→          source,
146→          message,
147→          projectName,
148→          runId,
149→        },
150→      ],
151→    }));
152→  }, []);
153→
154→  // Load all projects and their active runs on mount
155→  useEffect(() => {
156→    mountedRef.current = true;
157→    let cancelled = false;
158→
159→    async function loadAll() {
160→      try {
161→        const projects = await api.listProjects();
162→        if (cancelled) return;
163→
164→        const issueMap = new Map<number, Issue>();
165→        const runMap = new Map<number, PipelineRun>();
166→        const phaseMap = new Map<number, PipelinePhase[]>();
167→
168→        for (const project of projects) {
169→          try {
170→            const board = await api.getBoard(project.id);
171→            if (cancelled) return;
172→            for (const col of board.columns) {
173→              for (const item of col.issues) {
174→                issueMap.set(item.issue.id, item.issue);
175→                if (item.active_run) {
176→                  runMap.set(item.active_run.id, item.active_run);
177→                }
178→              }
179→            }
180→          } catch {
181→            // Skip projects that fail to load
182→          }
183→        }
184→
185→        // Backfill agent teams and events for active runs
186→        const teamMap = new Map<number, AgentTeamDetail>();
187→        const eventMap = new Map<number, AgentEvent[]>();
188→        for (const [runId, run] of runMap) {
189→          if (cancelled) return;
190→          if (run.status !== 'running' && run.status !== 'queued') continue;
191→          try {
192→            const detail = await api.getRunTeam(runId);
193→            if (cancelled) return;
194→            if (detail) {
195→              teamMap.set(runId, detail);
196→              for (const task of detail.tasks) {
197→                try {
198→                  const events = await api.getTaskEvents(task.id, 200);
199→                  if (cancelled) return;
200→                  if (events.length > 0) eventMap.set(task.id, events);
201→                } catch { /* skip */ }
202→              }
203→            }
204→          } catch { /* no team for this run */ }
205→        }
206→
207→        // Backfill phases for active runs
208→        for (const [runId, run] of runMap) {
209→          if (cancelled) return;
210→          if (run.status !== 'running' && run.status !== 'queued') continue;
211→          try {
212→            const runPhases = await api.getRunPhases(runId);
213→            if (cancelled) return;
214→            if (runPhases.length > 0) phaseMap.set(runId, runPhases);
215→          } catch { /* phases will arrive via WS */ }
216→        }
217→
218→        if (!cancelled) {
219→          setState(prev => ({
220→            ...prev,
221→            projects,
222→            issues: issueMap,
223→            runs: runMap,
224→            phases: phaseMap,
225→            agentTeams: teamMap,
226→            agentEvents: eventMap,
227→            loading: false,
228→          }));
229→          addLogEntry('system', `Loaded ${projects.length} projects, ${runMap.size} active runs`);
230→        }
231→      } catch (err) {
232→        if (!cancelled) {
233→          setState(prev => ({
234→            ...prev,
235→            loading: false,
236→            error: err instanceof Error ? err.message : 'Failed to load',
237→          }));
238→        }
239→      }
240→    }
241→
242→    loadAll();
243→    return () => { cancelled = true; mountedRef.current = false; };
244→  }, [addLogEntry]);
245→
246→  // WebSocket message handler — uses a ref for issues to avoid stale closure
247→  const issuesRef = useRef(state.issues);
248→  issuesRef.current = state.issues;
249→
250→  useWsSubscribe(useCallback((msg: WsMessage) => {
251→    if (!mountedRef.current) return;
252→
253→    switch (msg.type) {
254→      case 'PipelineStarted': {
255→        const run = msg.data.run;
256→        setState(prev => {
257→          const newRuns = new Map(prev.runs);
258→          newRuns.set(run.id, run);
259→          return { ...prev, runs: newRuns };
260→        });
261→        const issue = issuesRef.current.get(run.issue_id);
262→        addLogEntry('system', `Pipeline started for "${issue?.title ?? `issue #${run.issue_id}`}"`, undefined, run.id);
263→        break;
264→      }
265→
266→      case 'PipelineProgress': {
267→        const { run_id, phase, iteration } = msg.data;
268→        setState(prev => {
269→          const newRuns = new Map(prev.runs);
270→          const existing = newRuns.get(run_id);
271→          if (existing) {
272→            newRuns.set(run_id, { ...existing, current_phase: phase, iteration });
273→          }
274→          return { ...prev, runs: newRuns };
275→        });
276→        break;
277→      }
278→
279→      case 'PipelineCompleted': {
280→        const run = msg.data.run;
281→        setState(prev => {
282→          const newRuns = new Map(prev.runs);
283→          newRuns.set(run.id, run);
284→          return { ...prev, runs: newRuns };
285→        });
286→        addLogEntry('system', 'Pipeline completed successfully', undefined, run.id);
287→        break;
288→      }
289→
290→      case 'PipelineFailed': {
291→        const run = msg.data.run;
292→        setState(prev => {
293→          const newRuns = new Map(prev.runs);
294→          newRuns.set(run.id, run);
295→          return { ...prev, runs: newRuns };
296→        });
297→        addLogEntry('error', `Pipeline failed: ${run.error ?? 'unknown error'}`, undefined, run.id);
298→        break;
299→      }
300→
301→      case 'PipelineOutput': {
302→        const { run_id, content } = msg.data;
303→        setState(prev => {
304→          const newEvents = new Map(prev.pipelineEvents);
305→          const existing = newEvents.get(run_id) ?? [];
306→          const event: AgentEvent = {
307→            id: existing.length + 1,
308→            task_id: 0,
309→            event_type: 'output',
310→            content,
311→            metadata: null,
312→            created_at: new Date().toISOString(),
313→          };
314→          newEvents.set(run_id, [...existing.slice(-199), event]);
315→          return { ...prev, pipelineEvents: newEvents };
316→        });
317→        break;
318→      }
319→
320→      case 'PipelineOutputEvent': {
321→        const evt = msg.data;
322→        setState(prev => {
323→          const newOutputEvents = new Map(prev.pipelineOutputEvents);
324→          const existing = newOutputEvents.get(evt.run_id) ?? [];
325→          newOutputEvents.set(evt.run_id, [...existing.slice(-499), evt]);
326→          return { ...prev, pipelineOutputEvents: newOutputEvents };
327→        });
328→        // Also push to legacy pipelineEvents for backward compat
329→        setState(prev => {
330→          const newEvents = new Map(prev.pipelineEvents);
331→          const existing = newEvents.get(evt.run_id) ?? [];
332→          const event: AgentEvent = {
333→            id: existing.length + 1,
334→            task_id: 0,
335→            event_type: evt.content_type === 'thinking' ? 'thinking' : 'output',
336→            content: evt.content_type === 'tool_start'
337→              ? `[${evt.content}] ${evt.input_summary ?? ''}`
338→              : evt.content,
339→            metadata: null,
340→            created_at: new Date().toISOString(),
341→          };
342→          newEvents.set(evt.run_id, [...existing.slice(-199), event]);
343→          return { ...prev, pipelineEvents: newEvents };
344→        });
345→        break;
346→      }
347→
348→      case 'PipelineFileChanged': {
349→        const { run_id, file_path, action } = msg.data;
350→        setState(prev => {
351→          const newFileChanges = new Map(prev.pipelineFileChanges);
352→          const existing = newFileChanges.get(run_id) ?? [];
353→          // Deduplicate by file_path + action
354→          if (!existing.some(f => f.file_path === file_path && f.action === action)) {
355→            newFileChanges.set(run_id, [...existing, { run_id, file_path, action }]);
356→          }
357→          return { ...prev, pipelineFileChanges: newFileChanges };
358→        });
359→        break;
360→      }
361→
362→      case 'PipelinePhaseStarted': {
363→        const { run_id, phase_number, phase_name } = msg.data;
364→        setState(prev => {
365→          const newPhases = new Map(prev.phases);
366→          const existing = newPhases.get(run_id) ?? [];
367→          const newPhase: PipelinePhase = {
368→            id: 0,
369→            run_id,
370→            phase_number,
371→            phase_name,
372→            status: 'running',
373→            iteration: null,
374→            budget: null,
375→            started_at: new Date().toISOString(),
376→            completed_at: null,
377→            error: null,
378→          };
379→          if (existing.some(p => p.phase_number === phase_number)) return prev;
380→          newPhases.set(run_id, [...existing, newPhase]);
381→          return { ...prev, phases: newPhases };
382→        });
383→        addLogEntry('phase', `Phase "${phase_name}" started`, undefined, run_id);
384→        break;
385→      }
386→
387→      case 'PipelinePhaseCompleted': {
388→        const { run_id, phase_number, success } = msg.data;
389→        setState(prev => {
390→          const newPhases = new Map(prev.phases);
391→          const existing = newPhases.get(run_id) ?? [];
392→          newPhases.set(run_id, existing.map(p =>
393→            p.phase_number === phase_number
394→              ? { ...p, status: success ? 'completed' : 'failed', completed_at: new Date().toISOString() }
395→              : p
396→          ));
397→          return { ...prev, phases: newPhases };
398→        });
399→        addLogEntry('phase', `Phase completed (${success ? 'success' : 'failed'})`, undefined, run_id);
400→        break;
401→      }
402→
403→      case 'PipelineReviewStarted': {
404→        addLogEntry('review', 'Review started', undefined, msg.data.run_id);
405→        break;
406→      }
407→
408→      case 'PipelineReviewCompleted': {
409→        const { passed, findings_count } = msg.data;
410→        addLogEntry('review', `Review ${passed ? 'passed' : `failed (${findings_count} findings)`}`, undefined, msg.data.run_id);
411→        break;
412→      }
413→
414→      case 'PipelineBranchCreated': {
415→        const { run_id, branch_name } = msg.data;
416→        setState(prev => {
417→          const newRuns = new Map(prev.runs);
418→          const existing = newRuns.get(run_id);
419→          if (existing) {
420→            newRuns.set(run_id, { ...existing, branch_name });
421→          }
422→          return { ...prev, runs: newRuns };
423→        });
424→        addLogEntry('git', `Branch created: ${branch_name}`, undefined, run_id);
425→        break;
426→      }
427→
428→      case 'PipelinePrCreated': {
429→        const { run_id, pr_url } = msg.data;
430→        setState(prev => {
431→          const newRuns = new Map(prev.runs);
432→          const existing = newRuns.get(run_id);
433→          if (existing) {
434→            newRuns.set(run_id, { ...existing, pr_url });
435→          }
436→          return { ...prev, runs: newRuns };
437→        });
438→        addLogEntry('git', 'PR created', undefined, run_id);
439→        break;
440→      }
441→
442→      case 'TeamCreated': {
443→        const { run_id, team_id, strategy, isolation, plan_summary, tasks } = msg.data;
444→        setState(prev => {
445→          const newTeams = new Map(prev.agentTeams);
446→          newTeams.set(run_id, {
447→            team: { id: team_id, run_id, strategy, isolation, plan_summary, created_at: new Date().toISOString() },
448→            tasks: tasks ?? [],
449→          });
450→          return { ...prev, agentTeams: newTeams };
451→        });
452→        addLogEntry('agent', `Agent team created (${strategy})`, undefined, run_id);
453→        break;
454→      }
455→
456→      case 'AgentTaskStarted': {
457→        addLogEntry('agent', `Task "${msg.data.name}" started (${msg.data.role})`, undefined, undefined);
458→        break;
459→      }
460→
461→      case 'AgentThinking':
462→      case 'AgentAction':
463→      case 'AgentOutput':
464→      case 'AgentSignal': {
465→        const taskId = msg.data.task_id;
466→        setState(prev => {
467→          const newEvents = new Map(prev.agentEvents);
468→          const taskEvents = newEvents.get(taskId) ?? [];
469→          const event: AgentEvent = {
470→            id: taskEvents.length + 1,
471→            task_id: taskId,
472→            event_type: msg.type === 'AgentThinking' ? 'thinking'
473→              : msg.type === 'AgentAction' ? 'action'
474→              : msg.type === 'AgentOutput' ? 'output'
475→              : 'signal',
476→            content: msg.type === 'AgentAction' ? msg.data.summary : msg.data.content,
477→            metadata: msg.type === 'AgentAction' ? msg.data.metadata : null,
478→            created_at: new Date().toISOString(),
479→          };
480→          newEvents.set(taskId, [...taskEvents.slice(-199), event]);
481→          return { ...prev, agentEvents: newEvents };
482→        });
483→        break;
484→      }
485→
486→      case 'IssueCreated': {
487→        const issue = msg.data.issue;
488→        setState(prev => {
489→          const newIssues = new Map(prev.issues);
490→          newIssues.set(issue.id, issue);
491→          return { ...prev, issues: newIssues };
492→        });
493→        addLogEntry('system', `Issue created: "${issue.title}"`);
494→        break;
495→      }
496→
497→      case 'IssueDeleted': {
498→        setState(prev => {
499→          const newIssues = new Map(prev.issues);
500→          newIssues.delete(msg.data.issue_id);
501→          return { ...prev, issues: newIssues };
502→        });
503→        break;
504→      }
505→
506→      case 'ProjectCreated': {
507→        const project = msg.data.project;
508→        setState(prev => {
509→          if (prev.projects.some(p => p.id === project.id)) return prev;
510→          return { ...prev, projects: [...prev.projects, project] };
511→        });
512→        addLogEntry('system', `Project added: "${project.name}"`);
513→        break;
514→      }
515→
516→      case 'ProjectDeleted': {
517→        const deletedId = msg.data.project_id;
518→        setState(prev => {
519→          const newProjects = prev.projects.filter(p => p.id !== deletedId);
520→          const newIssues = new Map(prev.issues);
521→          const newRuns = new Map(prev.runs);
522→          // Remove issues belonging to the deleted project
523→          for (const [id, issue] of newIssues) {
524→            if (issue.project_id === deletedId) {
525→              // Also remove runs for this issue
526→              for (const [runId, run] of newRuns) {
527→                if (run.issue_id === id) newRuns.delete(runId);
528→              }
529→              newIssues.delete(id);
530→            }
531→          }
532→          return { ...prev, projects: newProjects, issues: newIssues, runs: newRuns };
533→        });
534→        addLogEntry('system', 'Project deleted');
535→        break;
536→      }
537→    }
538→  }, [addLogEntry]));
539→
540→  // Compute filtered and sorted agent run cards
541→  const agentRunCards: AgentRunCard[] = useMemo(() => {
542→    return Array.from(state.runs.values())
543→      .filter(run => {
544→        if (selectedProjectId !== null) {
545→          const issue = state.issues.get(run.issue_id);
546→          if (issue && issue.project_id !== selectedProjectId) return false;
547→        }
548→        if (statusFilter !== 'all' && run.status !== statusFilter) return false;
549→        return true;
550→      })
551→      .sort((a, b) => {
552→        const diff = (STATUS_ORDER[a.status] ?? 5) - (STATUS_ORDER[b.status] ?? 5);
553→        if (diff !== 0) return diff;
554→        return new Date(b.started_at).getTime() - new Date(a.started_at).getTime();
555→      })
556→      .map(run => ({
557→        run,
558→        issue: state.issues.get(run.issue_id) ?? {
559→          id: run.issue_id,
560→          project_id: 0,
561→          title: `Issue #${run.issue_id}`,
562→          description: '',
563→          column: 'backlog' as const,
564→          position: 0,
565→          priority: 'medium' as const,
566→          labels: [],
567→          github_issue_number: null,
568→          created_at: '',
569→          updated_at: '',
570→        },
571→        project: state.projects.find(p => {
572→          const issue = state.issues.get(run.issue_id);
573→          return issue && p.id === issue.project_id;
574→        }) ?? { id: 0, name: 'Unknown', path: '', github_repo: null, created_at: '' },
575→      }));
576→  }, [state.runs, state.issues, state.projects, selectedProjectId, statusFilter]);
577→
578→  // Compute idle issue cards — issues without any active pipeline run
579→  const idleIssueCards: IdleIssueCard[] = useMemo(() => {
580→    const issueIdsWithRuns = new Set(
581→      Array.from(state.runs.values()).map(r => r.issue_id)
582→    );
583→    return Array.from(state.issues.values())
584→      .filter(issue => {
585→        if (issueIdsWithRuns.has(issue.id)) return false;
586→        if (selectedProjectId !== null && issue.project_id !== selectedProjectId) return false;
587→        return true;
588→      })
589→      .map(issue => ({
590→        issue,
591→        project: state.projects.find(p => p.id === issue.project_id)
592→          ?? { id: 0, name: 'Unknown', path: '', github_repo: null, created_at: '' },
593→      }));
594→  }, [state.issues, state.runs, state.projects, selectedProjectId]);
595→
596→  // Compute status counts (unfiltered — always reflect total state)
597→  const statusCounts: Record<RunStatusFilter, number> = useMemo(() => {
598→    const runs = Array.from(state.runs.values());
599→    return {
600→      all: runs.length,
601→      running: runs.filter(r => r.status === 'running').length,
602→      queued: runs.filter(r => r.status === 'queued').length,
603→      completed: runs.filter(r => r.status === 'completed').length,
604→      failed: runs.filter(r => r.status === 'failed').length,
605→    };
606→  }, [state.runs]);
607→
608→  // Actions
609→  const triggerPipeline = useCallback(async (issueId: number) => {
610→    const run = await api.triggerPipeline(issueId);
611→    setState(prev => {
612→      const newRuns = new Map(prev.runs);
613→      newRuns.set(run.id, run);
614→      return { ...prev, runs: newRuns };
615→    });
616→  }, []);
617→
618→  const cancelPipeline = useCallback(async (runId: number) => {
619→    const run = await api.cancelPipelineRun(runId);
620→    setState(prev => {
621→      const newRuns = new Map(prev.runs);
622→      newRuns.set(run.id, run);
623→      return { ...prev, runs: newRuns };
624→    });
625→  }, []);
626→
627→  const createIssue = useCallback(async (projectId: number, title: string, description: string) => {
628→    const issue = await api.createIssue(projectId, title, description);
629→    setState(prev => {
630→      const newIssues = new Map(prev.issues);
631→      newIssues.set(issue.id, issue);
632→      return { ...prev, issues: newIssues };
633→    });
634→    return issue;
635→  }, []);
636→
637→  const createProject = useCallback(async (name: string, path: string) => {
638→    const project = await api.createProject(name, path);
639→    // State update handled by WebSocket ProjectCreated handler
640→    return project;
641→  }, []);
642→
643→  const cloneProject = useCallback(async (repoUrl: string) => {
644→    const project = await api.cloneProject(repoUrl);
645→    // State update handled by WebSocket ProjectCreated handler
646→    return project;
647→  }, []);
648→
649→  const deleteProject = useCallback(async (projectId: number) => {
650→    await api.deleteProject(projectId);
651→    // Optimistic removal — WS message will also trigger state cleanup
652→    setState(prev => ({
653→      ...prev,
654→      projects: prev.projects.filter(p => p.id !== projectId),
655→    }));
656→  }, []);
657→
658→  const refresh = useCallback(async () => {
659→    setState(prev => ({ ...prev, loading: true }));
660→    try {
661→      const projects = await api.listProjects();
662→      const issueMap = new Map<number, Issue>();
663→      const runMap = new Map<number, PipelineRun>();
664→      for (const project of projects) {
665→        try {
666→          const board = await api.getBoard(project.id);
667→          for (const col of board.columns) {
668→            for (const item of col.issues) {
669→              issueMap.set(item.issue.id, item.issue);
670→              if (item.active_run) {
671→                runMap.set(item.active_run.id, item.active_run);
672→              }
673→            }
674→          }
675→        } catch { /* skip */ }
676→      }
677→      const phaseMap = new Map<number, PipelinePhase[]>();
678→      for (const [runId, run] of runMap) {
679→        if (run.status !== 'running' && run.status !== 'queued') continue;
680→        try {
681→          const runPhases = await api.getRunPhases(runId);
682→          if (runPhases.length > 0) phaseMap.set(runId, runPhases);
683→        } catch { /* skip */ }
684→      }
685→      setState(prev => ({
686→        ...prev,
687→        projects,
688→        issues: issueMap,
689→        runs: runMap,
690→        phases: phaseMap,
691→        loading: false,
692→        error: null,
693→      }));
694→    } catch (err) {
695→      setState(prev => ({
696→        ...prev,
697→        loading: false,
698→        error: err instanceof Error ? err.message : 'Refresh failed',
699→      }));
700→    }
701→  }, []);
702→
703→  // Compute issue counts grouped by project ID
704→  const issuesByProject = useMemo(() => {
705→    const map = new Map<number, number>();
706→    for (const issue of state.issues.values()) {
707→      map.set(issue.project_id, (map.get(issue.project_id) ?? 0) + 1);
708→    }
709→    return map;
710→  }, [state.issues]);
711→
712→  return {
713→    projects: state.projects,
714→    agentRunCards,
715→    idleIssueCards,
716→    statusCounts,
717→    eventLog: state.eventLog,
718→    phases: state.phases,
719→    agentTeams: state.agentTeams,
720→    agentEvents: state.agentEvents,
721→    pipelineEvents: state.pipelineEvents,
722→    pipelineOutputEvents: state.pipelineOutputEvents,
723→    pipelineFileChanges: state.pipelineFileChanges,
724→    loading: state.loading,
725→    error: state.error,
726→    selectedProjectId,
727→    setSelectedProjectId,
728→    statusFilter,
729→    setStatusFilter,
730→    triggerPipeline,
731→    cancelPipeline,
732→    createIssue,
733→    createProject,
734→    cloneProject,
735→    deleteProject,
736→    refresh,
737→    issuesByProject,
738→  };
739→}
