  1→//! Swarm orchestration prompt templates.
  2→//!
  3→//! This module provides template functions for generating prompts sent to
  4→//! Claude Code when invoking swarm capabilities. These prompts instruct the
  5→//! swarm leader on how to coordinate parallel task execution.
  6→//!
  7→//! ## Prompt Types
  8→//!
  9→//! - **Orchestration prompt**: Main prompt for coordinating swarm execution
 10→//! - **Task prompt**: Individual task assignment for workers
 11→//! - **Review prompt**: Instructions for review specialists
 12→//! - **Progress reporting**: Format for callback updates
 13→
 14→use crate::swarm::context::{
 15→    PhaseInfo, ReviewConfig, ReviewSpecialistConfig, SwarmContext, SwarmStrategy, SwarmTask,
 16→};
 17→
 18→/// Build the main orchestration prompt for swarm execution.
 19→///
 20→/// This prompt is sent to Claude Code to initiate swarm coordination.
 21→/// It includes all context needed for the swarm leader to:
 22→/// - Create a team
 23→/// - Spawn worker agents
 24→/// - Distribute tasks
 25→/// - Monitor progress
 26→/// - Run reviews
 27→/// - Report completion
 28→pub fn build_orchestration_prompt(context: &SwarmContext) -> String {
 29→    let mut prompt = String::new();
 30→
 31→    // Header
 32→    prompt.push_str(&format!(
 33→        "# Forge Swarm Orchestrator\n\n\
 34→         You are coordinating a swarm for Forge phase {}: {}\n\n",
 35→        context.phase.number, context.phase.name
 36→    ));
 37→
 38→    // Context section
 39→    prompt.push_str("## Context\n\n");
 40→    prompt.push_str(&format!(
 41→        "- **Phase**: {} - {}\n",
 42→        context.phase.number, context.phase.name
 43→    ));
 44→    prompt.push_str(&format!("- **Promise**: `{}`\n", context.phase.promise));
 45→    prompt.push_str(&format!(
 46→        "- **Budget**: {} iterations ({} remaining)\n",
 47→        context.phase.budget,
 48→        context.phase.remaining_budget()
 49→    ));
 50→    prompt.push_str(&format!(
 51→        "- **Strategy**: {} - {}\n",
 52→        strategy_name(context.strategy),
 53→        context.strategy.description()
 54→    ));
 55→    prompt.push_str(&format!(
 56→        "- **Working Directory**: {}\n",
 57→        context.working_dir.display()
 58→    ));
 59→    prompt.push_str(&format!("- **Callback URL**: {}\n", context.callback_url));
 60→    prompt.push('\n');
 61→
 62→    // Additional context if provided
 63→    if let Some(additional) = &context.additional_context {
 64→        prompt.push_str("## Additional Instructions\n\n");
 65→        prompt.push_str(additional);
 66→        prompt.push_str("\n\n");
 67→    }
 68→
 69→    // Tasks section
 70→    if context.has_predefined_tasks() {
 71→        prompt.push_str("## Pre-defined Tasks\n\n");
 72→        prompt.push_str("Execute the following tasks according to the strategy:\n\n");
 73→        for task in &context.tasks {
 74→            prompt.push_str(&format_task(task));
 75→        }
 76→        prompt.push('\n');
 77→    } else {
 78→        prompt.push_str("## Task Discovery\n\n");
 79→        prompt.push_str(
 80→            "No pre-defined tasks. Analyze the phase requirements and decompose into \
 81→             appropriate sub-tasks before execution.\n\n",
 82→        );
 83→    }
 84→
 85→    // Reviews section
 86→    if let Some(reviews) = &context.reviews
 87→        && reviews.has_specialists()
 88→    {
 89→        prompt.push_str("## Reviews\n\n");
 90→        prompt.push_str(&format_review_config(reviews));
 91→        prompt.push('\n');
 92→    }
 93→
 94→    // Responsibilities section
 95→    prompt.push_str(&build_responsibilities_section(context));
 96→
 97→    // Progress reporting section
 98→    prompt.push_str(&build_progress_section(&context.callback_url));
 99→
100→    // Completion section
101→    prompt.push_str(&build_completion_section(&context.phase));
102→
103→    prompt
104→}
