106→/// Build the task assignment prompt for a worker agent.
107→///
108→/// This prompt is used when spawning a worker to execute a specific task.
109→pub fn build_task_prompt(task: &SwarmTask, phase: &PhaseInfo, callback_url: &str) -> String {
110→    let mut prompt = String::new();
111→
112→    prompt.push_str(&format!(
113→        "# Task: {}\n\n\
114→         You are executing task `{}` for Forge phase {} ({}).\n\n",
115→        task.name, task.id, phase.number, phase.name
116→    ));
117→
118→    prompt.push_str("## Description\n\n");
119→    prompt.push_str(&task.description);
120→    prompt.push_str("\n\n");
121→
122→    if !task.files.is_empty() {
123→        prompt.push_str("## Target Files\n\n");
124→        for file in &task.files {
125→            prompt.push_str(&format!("- `{}`\n", file));
126→        }
127→        prompt.push('\n');
128→    }
129→
130→    prompt.push_str(&format!(
131→        "## Budget\n\n\
132→         You have {} iterations to complete this task.\n\n",
133→        task.budget
134→    ));
135→
136→    prompt.push_str(&format!(
137→        "## Progress Reporting\n\n\
138→         Report progress to: `{}/progress`\n\n\
139→         ```bash\n\
140→         curl -X POST {}/progress -H 'Content-Type: application/json' \\\n\
141→           -d '{{\"task\": \"{}\", \"status\": \"in_progress\", \"percent\": 50}}'\n\
142→         ```\n\n",
143→        callback_url, callback_url, task.id
144→    ));
145→
146→    prompt.push_str(&format!(
147→        "## Completion\n\n\
148→         When done, report completion:\n\n\
149→         ```bash\n\
150→         curl -X POST {}/complete -H 'Content-Type: application/json' \\\n\
151→           -d '{{\"task\": \"{}\", \"status\": \"success\", \"summary\": \"Brief description\"}}'\n\
152→         ```\n\n\
153→         Then output:\n\
154→         ```\n\
155→         <task_complete id=\"{}\">SUCCESS</task_complete>\n\
156→         ```\n",
157→        callback_url, task.id, task.id
158→    ));
159→
160→    prompt
161→}
