 11→  if (secs < 3600) return `${Math.floor(secs / 60)}m ${Math.round(secs % 60)}s`;
 12→  const h = Math.floor(secs / 3600);
 13→  const m = Math.floor((secs % 3600) / 60);
 14→  return `${h}h ${m}m`;
