458→/// Parse a swarm completion signal from output.
459→///
460→/// Looks for `<swarm_complete>...</swarm_complete>` tags and parses the JSON inside.
461→pub fn parse_swarm_completion(output: &str) -> Option<SwarmCompletionResult> {
462→    let start_tag = "<swarm_complete>";
463→    let end_tag = "</swarm_complete>";
464→
465→    let start = output.find(start_tag)?;
466→    let end = output.find(end_tag)?;
467→
468→    if start >= end {
469→        return None;
470→    }
471→
472→    let json_start = start + start_tag.len();
473→    let json_content = output[json_start..end].trim();
474→
475→    serde_json::from_str(json_content).ok()
476→}
477→
478→/// Parse a task completion signal from output.
479→///
480→/// Looks for `<task_complete id="...">...</task_complete>` tags.
481→pub fn parse_task_completion(output: &str, task_id: &str) -> Option<String> {
482→    let pattern = format!("<task_complete id=\"{}\">", task_id);
483→    let end_tag = "</task_complete>";
484→
485→    let start = output.find(&pattern)?;
486→    let content_start = start + pattern.len();
487→    let end = output[content_start..].find(end_tag)?;
488→
489→    Some(
490→        output[content_start..content_start + end]
491→            .trim()
492→            .to_string(),
493→    )
494→}
