 99→/// Summary information about the phase being executed.
100→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
101→pub struct PhaseInfo {
102→    /// Phase number (e.g., "05", "05.1").
103→    pub number: String,
104→    /// Phase name/description.
105→    pub name: String,
106→    /// Promise tag that signals completion.
107→    pub promise: String,
108→    /// Total iteration budget.
109→    pub budget: u32,
110→    /// Iterations already used (if resuming).
111→    #[serde(default)]
112→    pub iterations_used: u32,
113→}
