115→impl PhaseInfo {
116→    /// Create a new phase info.
117→    pub fn new(number: &str, name: &str, promise: &str, budget: u32) -> Self {
118→        Self {
119→            number: number.to_string(),
120→            name: name.to_string(),
121→            promise: promise.to_string(),
