  1→/** Collapsible system-wide activity feed displaying timestamped events with color-coded source tags. */
  2→import { useState, useRef, useEffect } from 'react';
  3→import type { EventLogEntry } from '../types';
  4→
  5→/** Color map for event source tags, using CSS custom properties. */
  6→const SOURCE_COLORS: Record<EventLogEntry['source'], string> = {
  7→  agent: 'var(--color-accent)',
  8→  phase: 'var(--color-info)',
  9→  review: '#a371f7',
 10→  system: 'var(--color-text-secondary)',
 11→  error: 'var(--color-error)',
 12→  git: 'var(--color-warning)',
 13→};
 14→
 15→/** Props for the EventLog component. */
 16→export interface EventLogProps {
 17→  /** Array of event log entries to display. */
 18→  entries: EventLogEntry[];
 19→}
 20→
 21→/**
 22→ * Renders a collapsible event log panel with timestamped, color-coded entries.
 23→ * Auto-scrolls to the latest entry when new events arrive.
 24→ */
 25→export default function EventLog({ entries }: EventLogProps): React.JSX.Element {
 26→  const [collapsed, setCollapsed] = useState(false);
 27→  const scrollRef = useRef<HTMLDivElement>(null);
 28→
 29→  useEffect(() => {
 30→    if (!collapsed && scrollRef.current) {
 31→      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
 32→    }
 33→  }, [entries, collapsed]);
 34→
 35→  const formatTime = (iso: string): string => {
 36→    const d = new Date(iso);
 37→    return d.toLocaleTimeString('en-US', { hour12: false });
 38→  };
 39→
 40→  return (
 41→    <div style={{
 42→      borderTop: '1px solid var(--color-border)',
 43→      backgroundColor: 'var(--color-bg-card)',
 44→      flexShrink: 0,
 45→    }}>
 46→      {/* Header */}
 47→      <button
 48→        onClick={() => setCollapsed(!collapsed)}
 49→        style={{
 50→          width: '100%',
 51→          display: 'flex',
 52→          alignItems: 'center',
 53→          justifyContent: 'space-between',
 54→          padding: '6px 12px',
 55→          background: 'transparent',
 56→          border: 'none',
 57→          borderBottom: collapsed ? 'none' : '1px solid var(--color-border)',
 58→          color: 'var(--color-text-secondary)',
 59→          cursor: 'pointer',
 60→          fontSize: '11px',
 61→          fontFamily: 'inherit',
 62→          textTransform: 'uppercase',
 63→          letterSpacing: '1px',
 64→        }}
 65→      >
 66→        <span>Event Log ({entries.length})</span>
 67→        <span style={{
 68→          transform: collapsed ? 'rotate(180deg)' : 'rotate(0deg)',
 69→          transition: 'transform 0.2s',
 70→        }}>
 71→          ▼
 72→        </span>
 73→      </button>
 74→
 75→      {/* Log content */}
 76→      {!collapsed && (
 77→        <div
 78→          ref={scrollRef}
 79→          style={{
 80→            height: '150px',
 81→            overflowY: 'auto',
 82→            padding: '4px 12px',
 83→            fontSize: '12px',
 84→            lineHeight: '1.8',
 85→          }}
 86→        >
 87→          {entries.map(entry => (
 88→            <div key={entry.id} style={{ display: 'flex', gap: '8px' }}>
 89→              <span style={{ color: 'var(--color-text-secondary)', flexShrink: 0 }}>
 90→                {formatTime(entry.timestamp)}
 91→              </span>
 92→              <span style={{
 93→                color: SOURCE_COLORS[entry.source],
 94→                flexShrink: 0,
 95→                width: '60px',
 96→              }}>
 97→                [{entry.source}]
 98→              </span>
 99→              <span style={{ color: 'var(--color-text-primary)' }}>
100→                {entry.message}
101→              </span>
102→            </div>
103→          ))}
104→          {entries.length === 0 && (
105→            <span style={{ color: 'var(--color-text-secondary)' }}>
106→              No events yet...
107→            </span>
108→          )}
109→        </div>
110→      )}
111→    </div>
112→  );
113→}
