  1→import { useState, useEffect, useCallback, useRef } from 'react'
  2→import type { AgentTeamDetail, AgentEvent, WsMessage } from '../types'
  3→import { useWsSubscribe } from '../contexts/WebSocketContext'
  4→import { api } from '../api/client'
  5→
  6→interface MergeStatus {
  7→  wave: number
  8→  started: boolean
  9→  conflicts?: boolean
 10→  conflictFiles?: string[]
 11→}
 12→
 13→interface VerificationResult {
 14→  run_id: number
 15→  task_id: number
 16→  verification_type: string
 17→  passed: boolean
 18→  summary: string
 19→  screenshots: string[]
 20→  details: Record<string, unknown>
 21→}
 22→
 23→interface AgentTeamState {
 24→  agentTeam: AgentTeamDetail | null
 25→  agentEvents: Map<number, AgentEvent[]>
 26→  mergeStatus: MergeStatus | null
 27→  verificationResults: VerificationResult[]
 28→}
 29→
 30→export function useAgentTeam(activeRunId: number | null): AgentTeamState {
 31→  const [agentTeam, setAgentTeam] = useState<AgentTeamDetail | null>(null)
 32→  const [agentEvents, setAgentEvents] = useState<Map<number, AgentEvent[]>>(new Map())
 33→  const [mergeStatus, setMergeStatus] = useState<MergeStatus | null>(null)
 34→  const [verificationResults, setVerificationResults] = useState<VerificationResult[]>([])
 35→  const runIdRef = useRef(activeRunId)
 36→
 37→  // Reset when runId changes
 38→  useEffect(() => {
 39→    runIdRef.current = activeRunId
 40→    setAgentTeam(null)
 41→    setAgentEvents(new Map())
 42→    setMergeStatus(null)
 43→    setVerificationResults([])
 44→  }, [activeRunId])
 45→
 46→  // Fetch existing team data on mount (recovery after page refresh)
 47→  useEffect(() => {
 48→    if (!activeRunId) return
 49→    let cancelled = false
 50→    api.getRunTeam(activeRunId).then(detail => {
 51→      if (!cancelled && detail) {
 52→        setAgentTeam(detail)
 53→        for (const task of detail.tasks) {
 54→          api.getTaskEvents(task.id).then(events => {
 55→            if (!cancelled) {
 56→              setAgentEvents(prev => new Map(prev).set(task.id, events))
 57→            }
 58→          }).catch(err => {
 59→            console.error(`[useAgentTeam] Failed to load events for task ${task.id}:`, err)
 60→          })
 61→        }
 62→      }
 63→    }).catch(err => {
 64→      console.error(`[useAgentTeam] Failed to load team for run ${activeRunId}:`, err)
 65→    })
 66→    return () => { cancelled = true }
 67→  }, [activeRunId])
 68→
 69→  // Handle WS messages
 70→  const handleMessage = useCallback((msg: WsMessage) => {
 71→    if (!runIdRef.current) return
 72→    const runId = runIdRef.current
 73→
 74→    switch (msg.type) {
 75→      case 'TeamCreated': {
 76→        if (msg.data.run_id !== runId) return
 77→        setAgentTeam({
 78→          team: {
 79→            id: msg.data.team_id,
 80→            run_id: msg.data.run_id,
 81→            strategy: msg.data.strategy,
 82→            isolation: msg.data.isolation,
 83→            plan_summary: msg.data.plan_summary,
 84→            created_at: new Date().toISOString(),
 85→          },
 86→          tasks: msg.data.tasks,
 87→        })
 88→        break
 89→      }
 90→      case 'AgentTaskStarted': {
 91→        if (msg.data.run_id !== runId) return
 92→        setAgentTeam(prev => {
 93→          if (!prev) return prev
 94→          return {
 95→            ...prev,
 96→            tasks: prev.tasks.map(t =>
 97→              t.id === msg.data.task_id ? { ...t, status: 'running' as const, started_at: new Date().toISOString() } : t
 98→            ),
 99→          }
100→        })
101→        break
102→      }
103→      case 'AgentTaskCompleted': {
104→        if (msg.data.run_id !== runId) return
105→        setAgentTeam(prev => {
106→          if (!prev) return prev
107→          return {
108→            ...prev,
109→            tasks: prev.tasks.map(t =>
110→              t.id === msg.data.task_id ? { ...t, status: msg.data.success ? 'completed' as const : 'failed' as const, completed_at: new Date().toISOString() } : t
111→            ),
112→          }
113→        })
114→        break
115→      }
116→      case 'AgentTaskFailed': {
117→        if (msg.data.run_id !== runId) return
118→        setAgentTeam(prev => {
119→          if (!prev) return prev
120→          return {
121→            ...prev,
122→            tasks: prev.tasks.map(t =>
123→              t.id === msg.data.task_id ? { ...t, status: 'failed' as const, error: msg.data.error, completed_at: new Date().toISOString() } : t
124→            ),
125→          }
126→        })
127→        break
128→      }
129→      case 'AgentThinking':
130→      case 'AgentAction':
131→      case 'AgentOutput':
132→      case 'AgentSignal': {
133→        if (msg.data.run_id !== runId) return
134→        const taskId = msg.data.task_id
135→        const event: AgentEvent = {
136→          id: Date.now(),
137→          task_id: taskId,
138→          event_type: msg.type === 'AgentThinking' ? 'thinking'
139→            : msg.type === 'AgentAction' ? 'action'
140→            : msg.type === 'AgentSignal' ? 'signal'
141→            : 'output',
142→          content: 'content' in msg.data ? msg.data.content : ('summary' in msg.data ? msg.data.summary : ''),
143→          metadata: 'metadata' in msg.data ? msg.data.metadata : null,
144→          created_at: new Date().toISOString(),
145→        }
146→        setAgentEvents(prev => {
147→          const next = new Map(prev)
148→          const existing = next.get(taskId) || []
149→          next.set(taskId, [...existing, event])
150→          return next
151→        })
152→        break
153→      }
154→      case 'MergeStarted': {
155→        if (msg.data.run_id !== runId) return
156→        setMergeStatus({ wave: msg.data.wave, started: true })
157→        break
158→      }
159→      case 'MergeCompleted': {
160→        if (msg.data.run_id !== runId) return
161→        setMergeStatus(prev => prev ? { ...prev, started: false, conflicts: msg.data.conflicts } : null)
162→        break
163→      }
164→      case 'MergeConflict': {
165→        if (msg.data.run_id !== runId) return
166→        setMergeStatus(prev => prev ? { ...prev, conflicts: true, conflictFiles: msg.data.files } : null)
167→        break
168→      }
169→      case 'VerificationResult': {
170→        if (msg.data.run_id !== runId) return
171→        setVerificationResults(prev => [...prev, msg.data])
172→        break
173→      }
174→    }
175→  }, [])
176→
177→  useWsSubscribe(handleMessage)
178→
179→  return { agentTeam, agentEvents, mergeStatus, verificationResults }
180→}
181→

  1→import { createContext, useContext, useEffect, useRef, useState, useCallback } from 'react'
  2→import type { ReactNode } from 'react'
  3→import type { WsMessage } from '../types'
  4→
  5→export type ConnectionStatus = 'connecting' | 'connected' | 'disconnected' | 'failed'
  6→type Subscriber = (msg: WsMessage) => void
  7→
  8→interface WsContextValue {
  9→  subscribe: (fn: Subscriber) => () => void
 10→  status: ConnectionStatus
 11→}
 12→
 13→const WsContext = createContext<WsContextValue | null>(null)
 14→
 15→const MAX_RECONNECT_ATTEMPTS = 20
 16→
 17→export function WebSocketProvider({ url, children }: { url: string; children: ReactNode }) {
 18→  const [status, setStatus] = useState<ConnectionStatus>('disconnected')
 19→  const subscribersRef = useRef(new Set<Subscriber>())
 20→
 21→  useEffect(() => {
 22→    let ws: WebSocket | null = null
 23→    let reconnectTimeout: number | undefined
 24→    let reconnectAttempt = 0
 25→    let cancelled = false
 26→
 27→    function connect() {
 28→      if (cancelled) return
 29→      try {
 30→        ws = new WebSocket(url)
 31→        setStatus('connecting')
 32→
 33→        ws.onopen = () => {
 34→          setStatus('connected')
 35→          reconnectAttempt = 0
 36→        }
 37→
 38→        ws.onmessage = (event) => {
 39→          let message: WsMessage
 40→          try {
 41→            message = JSON.parse(event.data)
 42→          } catch (err) {
 43→            console.warn('[ws] Failed to parse WebSocket message:', err, 'Raw:', typeof event.data === 'string' ? event.data.substring(0, 200) : typeof event.data)
 44→            return
 45→          }
 46→          subscribersRef.current.forEach(fn => {
 47→            try {
 48→              fn(message)
 49→            } catch (err) {
 50→              console.error('[ws] Subscriber error handling message type:', message.type, err)
 51→            }
 52→          })
 53→        }
 54→
 55→        ws.onclose = () => {
 56→          ws = null
 57→          if (reconnectAttempt >= MAX_RECONNECT_ATTEMPTS) {
 58→            console.error('[ws] Max reconnection attempts reached — giving up')
 59→            setStatus('failed')
 60→            return
 61→          }
 62→          setStatus('disconnected')
 63→          const delay = Math.min(1000 * Math.pow(2, reconnectAttempt), 30000)
 64→          reconnectAttempt += 1
 65→          reconnectTimeout = window.setTimeout(connect, delay)
 66→        }
 67→
 68→        ws.onerror = (event) => {
 69→          console.error('[ws] WebSocket error:', event)
 70→          ws?.close()
 71→        }
 72→      } catch (err) {
 73→        console.error('[ws] Failed to create WebSocket connection:', err)
 74→        if (reconnectAttempt >= MAX_RECONNECT_ATTEMPTS) {
 75→          console.error('[ws] Max reconnection attempts reached — giving up')
 76→          setStatus('failed')
 77→          return
 78→        }
 79→        setStatus('disconnected')
 80→        const delay = Math.min(1000 * Math.pow(2, reconnectAttempt), 30000)
 81→        reconnectAttempt += 1
 82→        reconnectTimeout = window.setTimeout(connect, delay)
 83→      }
 84→    }
 85→
 86→    connect()
 87→
 88→    return () => {
 89→      cancelled = true
 90→      if (reconnectTimeout) clearTimeout(reconnectTimeout)
 91→      ws?.close()
 92→    }
 93→  }, [url])
 94→
 95→  const subscribe = useCallback((fn: Subscriber) => {
 96→    subscribersRef.current.add(fn)
 97→    return () => { subscribersRef.current.delete(fn) }
 98→  }, [])
 99→
100→  return (

