/// Build and return the complete Axum router for the Factory API.
///
/// All routes are prefixed with `/api/` except `/health`.
///
/// | Method | Route                           | Handler description       |
/// |--------|---------------------------------|---------------------------|
/// | GET    | `/api/projects`                 | List all projects         |
/// | POST   | `/api/projects`                 | Create a project          |
/// | POST   | `/api/projects/clone`           | Clone a GitHub repo       |
/// | GET    | `/api/projects/:id`             | Get project details       |
/// | GET    | `/api/projects/:id/board`       | Get Kanban board state    |
/// | POST   | `/api/projects/:id/sync-github` | Sync issues from GitHub   |
/// | POST   | `/api/projects/:id/issues`      | Create an issue           |
/// | GET    | `/api/issues/:id`               | Get issue detail          |
/// | PATCH  | `/api/issues/:id`               | Update issue title/body   |
/// | DELETE | `/api/issues/:id`               | Delete an issue           |
/// | PATCH  | `/api/issues/:id/move`          | Move to column/position   |
/// | POST   | `/api/issues/:id/run`           | Trigger pipeline          |
/// | GET    | `/api/runs/:id`                 | Get pipeline run status   |
/// | POST   | `/api/runs/:id/cancel`          | Cancel a running pipeline |
/// | GET    | `/api/runs/:id/team`            | Get agent team for run    |
/// | GET    | `/api/runs/:id/phases`          | Get pipeline run phases   |
/// | GET    | `/api/tasks/:id/events`         | Get agent task events     |
/// | GET    | `/api/github/status`            | GitHub OAuth status       |
/// | POST   | `/api/github/device-code`       | Initiate device flow      |
/// | POST   | `/api/github/poll`              | Poll device code status   |
/// | POST   | `/api/github/connect`           | Connect with PAT token    |
/// | GET    | `/api/github/repos`             | List user's GitHub repos  |
/// | POST   | `/api/github/disconnect`        | Remove GitHub token       |
/// | GET    | `/api/cli-help`                 | Parsed CLI help data      |
/// | GET    | `/health`                       | Liveness probe            |
pub fn api_router() -> Router<SharedState> {
    Router::new()
        .route("/api/projects", get(list_projects).post(create_project))
        .route("/api/projects/clone", post(clone_project))
        .route(
            "/api/projects/{id}",
            get(get_project).delete(delete_project),
        )
        .route("/api/projects/{id}/board", get(get_board))
        .route("/api/projects/{id}/sync-github", post(sync_github_issues))
        .route("/api/projects/{id}/issues", post(create_issue))
        .route(
            "/api/issues/{id}",
            get(get_issue).patch(update_issue).delete(delete_issue),
        )
        .route("/api/issues/{id}/move", patch(move_issue))
        .route("/api/issues/{id}/run", post(trigger_pipeline))
        .route("/api/runs/{id}", get(get_pipeline_run))
        .route("/api/runs/{id}/cancel", post(cancel_pipeline_run))
        .route("/api/runs/{id}/team", get(get_run_team))
        .route("/api/runs/{id}/phases", get(get_run_phases))
        .route("/api/tasks/{id}/events", get(get_task_events))
        .route("/api/github/status", get(github_status))
        .route("/api/github/device-code", post(github_device_code))
        .route("/api/github/poll", post(github_poll_token))
        .route("/api/github/connect", post(github_connect_token))
        .route("/api/github/repos", get(github_list_repos))
        .route("/api/github/disconnect", post(github_disconnect))
        .route("/api/screenshots/{*path}", get(serve_screenshot))
        .route("/api/cli-help", get(cli_help_handler))
        .route("/api/metrics/summary", get(get_metrics_summary))
        .route("/api/metrics/phases", get(get_metrics_phases))
        .route("/api/metrics/reviews", get(get_metrics_reviews))
        .route("/api/metrics/tokens", get(get_metrics_tokens))
        .route("/api/metrics/runs/recent", get(get_metrics_recent_runs))
        .route("/health", get(health_check))
}

