/// `POST /api/issues/:id/run` — start a Forge pipeline run for an issue.
///
/// Creates a new `PipelineRun` record then spawns pipeline execution in a background
/// Tokio task. Emits real-time status updates via WebSocket.
///
/// **Response:** `201 Created` with the new `PipelineRun` as JSON.
///
/// **Errors:**
/// - `404 Not Found` if the issue does not exist
/// - `500 Internal Server Error` if the runner fails to start
async fn trigger_pipeline(
    State(state): State<SharedState>,
    Path(issue_id): Path<i64>,
) -> Result<impl IntoResponse, ApiError> {
    let (run, issue) = state
        .db
        .call(move |db| {
            let issue = db
                .get_issue(issue_id)?
                .ok_or_else(|| anyhow::anyhow!("Issue {} not found", issue_id))?;
            let run = db.create_pipeline_run(issue_id)?;
            Ok((run, issue))
        })
        .await
        .map_err(|e| {
            let msg = e.to_string();
            if msg.contains("not found") {
                ApiError::from(FactoryError::IssueNotFound { id: issue_id })
            } else {
                ApiError::Internal(msg)
            }
        })?;

    // Start pipeline execution in a background task
    let run_id = run.id;
    state
        .pipeline_runner
        .start_run(run_id, &issue, state.db.clone(), state.ws_tx.clone())
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;

    // Re-fetch the run after start_run (which updates status to Running)
    let updated_run = state
        .db
        .call(move |db| {
            db.get_pipeline_run(run_id)?
                .ok_or_else(|| anyhow::anyhow!("Pipeline run {} not found", run_id))
        })
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;

    Ok((StatusCode::CREATED, Json(updated_run)))
}

