async fn serve_screenshot(
    State(state): State<SharedState>,
    Path(file_path): Path<String>,
) -> Result<impl IntoResponse, ApiError> {
    let project_path = state
        .db
        .call(|db| {
            let projects = db.list_projects()?;
            projects
                .first()
                .map(|p| p.path.clone())
                .ok_or_else(|| anyhow::anyhow!("No projects"))
        })
        .await
        .map_err(|e| ApiError::NotFound(e.to_string()))?;

    let screenshots_dir = std::path::PathBuf::from(&project_path).join(".forge/screenshots");
    let full_path = screenshots_dir.join(&file_path);

    // Verify resolved path is within screenshots directory (prevents path traversal)
    let canonical_dir = tokio::fs::canonicalize(&screenshots_dir)
        .await
        .map_err(|_| ApiError::NotFound("Screenshots directory not found".into()))?;
    let canonical_file = tokio::fs::canonicalize(&full_path)
        .await
        .map_err(|_| ApiError::NotFound(format!("Screenshot not found: {}", file_path)))?;
    if !canonical_file.starts_with(&canonical_dir) {
        return Err(ApiError::BadRequest("Invalid path".into()));
    }

    let content_type = match full_path.extension().and_then(|e| e.to_str()) {
        Some("png") => "image/png",
        Some("jpg" | "jpeg") => "image/jpeg",
        Some("gif") => "image/gif",
        Some("webp") => "image/webp",
        _ => "application/octet-stream",
    };

    let bytes = tokio::fs::read(&full_path)
        .await
        .map_err(|e| ApiError::Internal(format!("Failed to read screenshot: {}", e)))?;

    Ok((
        StatusCode::OK,
        [(axum::http::header::CONTENT_TYPE, content_type)],
        bytes,
    ))
}

// ── GitHub OAuth handlers ─────────────────────────────────────────────

/// `GET /api/github/status` — report GitHub OAuth connection status.
///
/// **Response:** `200 OK` with `{ "connected": bool, "client_id_configured": bool }`.
async fn github_status(State(state): State<SharedState>) -> Result<impl IntoResponse, ApiError> {
    let connected = state
        .github_token
        .lock()
        .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?
        .is_some();
    let client_id_configured = state.github_client_id.is_some();
    Ok(Json(GitHubAuthStatus {
        connected,
        client_id_configured,
    }))
}

/// `POST /api/github/device-code` — initiate the GitHub Device Authorization Flow.
///
/// Requires `GITHUB_CLIENT_ID` env var to be set at server startup.
/// The client should display `verification_uri` + `user_code` to the user,
/// then poll `POST /api/github/poll` every `interval` seconds.
///
/// **Errors:** `400 Bad Request` if `GITHUB_CLIENT_ID` is not configured.
async fn github_device_code(
    State(state): State<SharedState>,
) -> Result<impl IntoResponse, ApiError> {
    let client_id = state
        .github_client_id
        .as_deref()
        .ok_or_else(|| ApiError::BadRequest("GITHUB_CLIENT_ID not configured".into()))?;
    let resp = super::github::request_device_code(client_id)
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;
    Ok(Json(resp))
}

/// `POST /api/github/poll` — poll for a GitHub device flow access token.
///
/// **Request body:**
/// ```json
/// { "device_code": "<code from device-code response>" }
/// ```
///
/// **Response:** `200 OK` with `{ "status": "complete" }` when the token is available,
/// or `{ "status": "pending" }` while the user has not yet authorized.
///
/// **Errors:** `400 Bad Request` if `GITHUB_CLIENT_ID` is not configured.
async fn github_poll_token(
    State(state): State<SharedState>,
    Json(req): Json<PollTokenRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let client_id = state
        .github_client_id
        .as_deref()
        .ok_or_else(|| ApiError::BadRequest("GITHUB_CLIENT_ID not configured".into()))?;
    match super::github::poll_for_token(client_id, &req.device_code)
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?
    {
        Some(token) => {
            let mut gh_token = state
                .github_token
                .lock()
                .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?;
            *gh_token = Some(token);
            Ok(Json(serde_json::json!({"status": "complete"})))
        }
        None => Ok(Json(serde_json::json!({"status": "pending"}))),
    }
}

/// `GET /api/github/repos` — list the authenticated user's GitHub repositories.
///
/// Requires a connected GitHub token.
///
/// **Response:** `200 OK` with a JSON array of repository objects.
///
/// **Errors:**
/// - `400 Bad Request` if not connected to GitHub
async fn github_list_repos(
    State(state): State<SharedState>,
) -> Result<impl IntoResponse, ApiError> {
    let token = state
        .github_token
        .lock()
        .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?
        .clone()
        .ok_or_else(|| ApiError::BadRequest("Not connected to GitHub".into()))?;
    let repos = super::github::list_repos(&token, 1, 100)
        .await
        .map_err(|e| ApiError::Internal(e.to_string()))?;
    Ok(Json(repos))
}

/// `POST /api/github/connect` — connect to GitHub using a Personal Access Token (PAT).
///
/// Validates the token by calling the GitHub API before storing it.
///
/// **Request body:**
/// ```json
/// { "token": "ghp_..." }
/// ```
///
/// **Response:** `200 OK` with `{ "status": "connected" }`.
///
/// **Errors:**
/// - `400 Bad Request` if the token is empty or fails GitHub validation
async fn github_connect_token(
    State(state): State<SharedState>,
    Json(req): Json<ConnectTokenRequest>,
) -> Result<impl IntoResponse, ApiError> {
    let token = req.token.trim().to_string();
    if token.is_empty() {
        return Err(ApiError::BadRequest("Token is required".into()));
    }
    // Validate the token by attempting to list repos
    super::github::list_repos(&token, 1, 1).await.map_err(|_| {
        ApiError::BadRequest("Invalid token — could not authenticate with GitHub".into())
    })?;
    let token_for_db = token.clone();
    {
        let mut gh_token = state
            .github_token
            .lock()
            .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?;
        *gh_token = Some(token);
    }
    // Persist token to DB settings
    state
        .db
        .call(move |db| db.set_setting("github_token", &token_for_db))
        .await
        .map_err(|e| ApiError::Internal(format!("Failed to persist token: {}", e)))?;
    Ok(Json(serde_json::json!({"status": "connected"})))
}

/// `POST /api/github/disconnect` — remove the stored GitHub token.
///
/// Clears the token from in-memory state and deletes it from the DB settings table.
///
/// **Response:** `200 OK` with `{ "status": "disconnected" }`.
async fn github_disconnect(
    State(state): State<SharedState>,
) -> Result<impl IntoResponse, ApiError> {
    {
        let mut token = state
            .github_token
            .lock()
            .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?;
        *token = None;
    }
    state
        .db
        .call(move |db| db.delete_setting("github_token"))
        .await
        .map_err(|e| ApiError::Internal(format!("Failed to delete token: {}", e)))?;
    Ok(Json(serde_json::json!({"status": "disconnected"})))
}

