use std::collections::HashMap;
use std::str::FromStr;
use std::sync::{Arc, Mutex, OnceLock};

use crate::errors::FactoryError;

use axum::{
    Json, Router,
    extract::{Path, Query, State},
    http::StatusCode,
    response::{IntoResponse, Response},
    routing::{get, patch, post},
};
use serde::Deserialize;
use tokio::sync::broadcast;

use super::db::DbHandle;
#[cfg(test)]
use super::db::FactoryDb;
use super::models::IssueColumn;
use super::pipeline::PipelineRunner;
use super::ws::{WsMessage, broadcast_message};
use crate::metrics::MetricsCollector;

// ── Shared application state ──────────────────────────────────────────

pub struct AppState {
    pub db: DbHandle,
    pub ws_tx: broadcast::Sender<String>,
    pub pipeline_runner: PipelineRunner,
    pub github_client_id: Option<String>,
    pub github_token: Mutex<Option<String>>,
    pub metrics: MetricsCollector,
}

pub type SharedState = Arc<AppState>;

// ── Request payload types ─────────────────────────────────────────────

#[derive(Deserialize)]
pub struct CreateProjectRequest {
    pub name: String,
    pub path: String,
}

#[derive(Deserialize)]
pub struct CloneProjectRequest {
    pub repo_url: String,
}

#[derive(Deserialize)]
pub struct CreateIssueRequest {
    pub title: String,
    pub description: Option<String>,
    pub column: Option<String>,
}

#[derive(Deserialize)]
pub struct UpdateIssueRequest {
    pub title: Option<String>,
    pub description: Option<String>,
    pub priority: Option<String>,
    pub labels: Option<String>,
}

#[derive(Deserialize)]
pub struct MoveIssueRequest {
    pub column: String,
    pub position: i32,
}

#[derive(Deserialize)]
pub struct PollTokenRequest {
    pub device_code: String,
}

#[derive(Deserialize)]
pub struct ConnectTokenRequest {
    pub token: String,
}

#[derive(serde::Serialize)]
pub struct GitHubAuthStatus {
    pub connected: bool,
    pub client_id_configured: bool,
}

#[derive(serde::Serialize)]
pub struct SyncResult {
    pub imported: usize,
    pub skipped: usize,
    pub total_github: usize,
}

#[derive(Clone, serde::Serialize)]
pub struct CliCommand {
    pub name: String,
    pub description: String,
}

#[derive(Clone, serde::Serialize)]
pub struct CliOption {
    pub flag: String,
    pub description: String,
}

#[derive(Clone, serde::Serialize)]
pub struct CliHelpResponse {
    pub commands: Vec<CliCommand>,
    pub options: Vec<CliOption>,
}

#[derive(serde::Serialize)]
pub struct AgentInfo {
    pub id: String,
    pub name: String,
    pub description: String,
    pub focus_areas: Vec<String>,
    pub default_gating: bool,
}

// ── Error handling ────────────────────────────────────────────────────

pub enum ApiError {
    NotFound(String),
    BadRequest(String),
    Internal(String),
}

impl IntoResponse for ApiError {
    fn into_response(self) -> Response {
        let (status, message) = match self {
            ApiError::NotFound(msg) => (StatusCode::NOT_FOUND, msg),
            ApiError::BadRequest(msg) => (StatusCode::BAD_REQUEST, msg),
            ApiError::Internal(msg) => (StatusCode::INTERNAL_SERVER_ERROR, msg),
        };
        (status, Json(serde_json::json!({"error": message}))).into_response()
    }
}

impl From<FactoryError> for ApiError {
    fn from(e: FactoryError) -> Self {
        match e {
            FactoryError::ProjectNotFound { id } => {
                ApiError::NotFound(format!("Project {} not found", id))
            }
            FactoryError::IssueNotFound { id } => {
                ApiError::NotFound(format!("Issue {} not found", id))
            }
            FactoryError::RunNotFound { id } => {
                ApiError::NotFound(format!("Pipeline run {} not found", id))
            }
            FactoryError::LockPoisoned => ApiError::Internal("Internal lock poisoned".to_string()),
            FactoryError::BadRequest(msg) => ApiError::BadRequest(msg),
            FactoryError::InvalidColumn { column, message } => {
                ApiError::BadRequest(format!("Invalid column '{}': {}", column, message))
            }
            FactoryError::PipelineAlreadyRunning { issue_id } => {
                ApiError::BadRequest(format!("Pipeline already running for issue {}", issue_id))
            }
            FactoryError::GitHub(msg) => ApiError::Internal(format!("GitHub API error: {}", msg)),
            FactoryError::Database(e) => ApiError::Internal(e.to_string()),
            FactoryError::Other(e) => ApiError::Internal(e.to_string()),
        }
    }
}

// ── Router ────────────────────────────────────────────────────────────

/// Build and return the complete Axum router for the Factory API.
///
/// All routes are prefixed with `/api/` except `/health`.
///
/// | Method | Route                           | Handler description       |
/// |--------|---------------------------------|---------------------------|
/// | GET    | `/api/projects`                 | List all projects         |
/// | POST   | `/api/projects`                 | Create a project          |
/// | POST   | `/api/projects/clone`           | Clone a GitHub repo       |
/// | GET    | `/api/projects/:id`             | Get project details       |
/// | GET    | `/api/projects/:id/board`       | Get Kanban board state    |
/// | POST   | `/api/projects/:id/sync-github` | Sync issues from GitHub   |
/// | POST   | `/api/projects/:id/issues`      | Create an issue           |
/// | GET    | `/api/issues/:id`               | Get issue detail          |
/// | PATCH  | `/api/issues/:id`               | Update issue title/body   |
/// | DELETE | `/api/issues/:id`               | Delete an issue           |
/// | PATCH  | `/api/issues/:id/move`          | Move to column/position   |
/// | POST   | `/api/issues/:id/run`           | Trigger pipeline          |
/// | GET    | `/api/runs/:id`                 | Get pipeline run status   |
/// | POST   | `/api/runs/:id/cancel`          | Cancel a running pipeline |
/// | GET    | `/api/runs/:id/team`            | Get agent team for run    |
/// | GET    | `/api/runs/:id/phases`          | Get pipeline run phases   |
/// | GET    | `/api/tasks/:id/events`         | Get agent task events     |
/// | GET    | `/api/github/status`            | GitHub OAuth status       |
/// | POST   | `/api/github/device-code`       | Initiate device flow      |
/// | POST   | `/api/github/poll`              | Poll device code status   |
/// | POST   | `/api/github/connect`           | Connect with PAT token    |
/// | GET    | `/api/github/repos`             | List user's GitHub repos  |
/// | POST   | `/api/github/disconnect`        | Remove GitHub token       |
/// | GET    | `/api/cli-help`                 | Parsed CLI help data      |
/// | GET    | `/health`                       | Liveness probe            |
pub fn api_router() -> Router<SharedState> {
    Router::new()
        .route("/api/projects", get(list_projects).post(create_project))
        .route("/api/projects/clone", post(clone_project))
        .route(
            "/api/projects/{id}",
            get(get_project).delete(delete_project),
        )
        .route("/api/projects/{id}/board", get(get_board))
        .route("/api/projects/{id}/sync-github", post(sync_github_issues))
        .route("/api/projects/{id}/issues", post(create_issue))
        .route(
            "/api/issues/{id}",
            get(get_issue).patch(update_issue).delete(delete_issue),
        )
        .route("/api/issues/{id}/move", patch(move_issue))
        .route("/api/issues/{id}/run", post(trigger_pipeline))
        .route("/api/runs/{id}", get(get_pipeline_run))
        .route("/api/runs/{id}/cancel", post(cancel_pipeline_run))
        .route("/api/runs/{id}/team", get(get_run_team))
        .route("/api/runs/{id}/phases", get(get_run_phases))
        .route("/api/tasks/{id}/events", get(get_task_events))
        .route("/api/github/status", get(github_status))
        .route("/api/github/device-code", post(github_device_code))
        .route("/api/github/poll", post(github_poll_token))
        .route("/api/github/connect", post(github_connect_token))
        .route("/api/github/repos", get(github_list_repos))
        .route("/api/github/disconnect", post(github_disconnect))
        .route("/api/screenshots/{*path}", get(serve_screenshot))
        .route("/api/agents", get(list_agents))
        .route("/api/cli-help", get(cli_help_handler))
        .route("/api/metrics/summary", get(get_metrics_summary))
        .route("/api/metrics/phases", get(get_metrics_phases))
        .route("/api/metrics/reviews", get(get_metrics_reviews))
        .route("/api/metrics/tokens", get(get_metrics_tokens))
        .route("/api/metrics/runs/recent", get(get_metrics_recent_runs))
        .route("/health", get(health_check))
}

// ── Helpers ───────────────────────────────────────────────────────────

/// Extract "owner/repo" from various GitHub URL formats.
fn parse_github_owner_repo(url: &str) -> Option<String> {
    let url = url.trim().trim_end_matches('/').trim_end_matches(".git");
    // Handle https://github.com/owner/repo and https://TOKEN@github.com/owner/repo
    if let Some(github_pos) = url.find("github.com/") {
        let rest = &url[github_pos + "github.com/".len()..];
        let parts: Vec<&str> = rest.splitn(3, '/').collect();
        if parts.len() >= 2 && !parts[0].is_empty() && !parts[1].is_empty() {
            return Some(format!("{}/{}", parts[0], parts[1]));
        }
    }
    if let Some(rest) = url.strip_prefix("git@github.com:") {
        let parts: Vec<&str> = rest.splitn(3, '/').collect();
        if parts.len() >= 2 {
            return Some(format!("{}/{}", parts[0], parts[1]));
        }
    }
    // Bare "owner/repo" format
    let parts: Vec<&str> = url.splitn(3, '/').collect();
    if parts.len() == 2 && !parts[0].contains(':') && !parts[0].contains('.') {
        return Some(format!("{}/{}", parts[0], parts[1]));
    }
    None
}

/// Shared sync logic used by both the endpoint handler and auto-sync after clone.
async fn do_sync_github_issues(
    state: &SharedState,
    project_id: i64,
) -> Result<SyncResult, ApiError> {
    let github_repo = {
        let (existing_repo, project_path) = state
            .db
            .call(move |db| {
                let project = db
                    .get_project(project_id)?
                    .ok_or_else(|| anyhow::anyhow!("Project {} not found", project_id))?;
                Ok((project.github_repo.clone(), project.path.clone()))
            })
            .await
            .map_err(|e| {
                let msg = e.to_string();
                if msg.contains("not found") {
                    ApiError::from(FactoryError::ProjectNotFound { id: project_id })
                } else {
                    ApiError::Internal(msg)
                }
            })?;

        match existing_repo {
            Some(repo) => repo,
            None => {
                // Try to detect github_repo from git remote (async to avoid blocking)
                let detected = detect_github_repo_from_path(&project_path).await;
                if let Some(ref owner_repo) = detected {
                    let owner_repo = owner_repo.clone();
                    let _ = state
                        .db
                        .call(move |db| db.update_project_github_repo(project_id, &owner_repo))
                        .await;
                }
                detected.ok_or_else(|| {
                    ApiError::BadRequest(
                        "Project has no GitHub repo configured and could not detect one from git remotes".into(),
                    )
                })?
            }
        }
    };

    let token = state
        .github_token
        .lock()
        .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?
        .clone()
        .ok_or_else(|| ApiError::BadRequest("Not connected to GitHub".into()))?;

    let gh_issues = super::github::list_issues(&token, &github_repo)
        .await
        .map_err(|e| ApiError::Internal(format!("Failed to fetch GitHub issues: {}", e)))?;

    let total_github = gh_issues.len();
    let mut imported = 0usize;
    let mut skipped = 0usize;

    {
        // Collect data needed for DB closure (must be owned)
        let gh_data: Vec<(String, String, i64)> = gh_issues
            .iter()
            .map(|gh| {
                (
                    gh.title.clone(),
                    gh.body.clone().unwrap_or_default(),
                    gh.number,
                )
            })
            .collect();

        let results = state
            .db
            .call(move |db| {
                let mut created = Vec::new();
                for (title, body, number) in &gh_data {
                    let result = db.create_issue_from_github(project_id, title, body, *number)?;
                    created.push(result);
                }
                Ok(created)
            })
            .await
            .map_err(|e| ApiError::Internal(e.to_string()))?;

        for result in results {
            match result {
                Some(issue) => {
                    broadcast_message(&state.ws_tx, &WsMessage::IssueCreated { issue });
                    imported += 1;
                }
                None => {
                    skipped += 1;
                }
            }
        }
    }

    Ok(SyncResult {
        imported,
        skipped,
        total_github,
    })
}

/// Try to detect "owner/repo" from git remote URLs in a local repo path.
async fn detect_github_repo_from_path(path: &str) -> Option<String> {
    let output = tokio::process::Command::new("git")
        .args(["-C", path, "remote", "get-url", "origin"])
        .output()
        .await
        .ok()?;
    if !output.status.success() {
        return None;
    }
    let url = String::from_utf8_lossy(&output.stdout).trim().to_string();
    parse_github_owner_repo(&url)
}

