                    padding: '12px',
                    gap: '12px',
                  }}>
                    {/* Idle dot */}
                    <span style={{
                      width: '8px',
                      height: '8px',
                      borderRadius: '50%',
                      backgroundColor: 'var(--color-text-secondary)',
                      flexShrink: 0,
                    }} />

                    {/* Project badge + issue title */}
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span style={{
                          fontSize: '10px',
                          padding: '1px 6px',
                          backgroundColor: 'var(--color-border)',
                          color: 'var(--color-text-secondary)',
                          textTransform: 'uppercase',
                          letterSpacing: '0.5px',
                          flexShrink: 0,
                        }}>
                          {project.name}
                        </span>
                        <span style={{
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          whiteSpace: 'nowrap',
                          fontSize: '13px',
                        }}>
                          {issue.title}
                        </span>
                      </div>
                    </div>

                    {/* Status label */}
                    <span style={{
                      fontSize: '11px',
                      color: 'var(--color-text-secondary)',
                      fontWeight: 600,
                      flexShrink: 0,
                    }}>
                      IDLE
                    </span>

                    {/* Run button */}
                    <button
                      onClick={() => triggerPipeline(issue.id)}
                      style={{
                        padding: '4px 12px',
                        fontSize: '11px',
                        fontFamily: 'inherit',
                        background: 'transparent',
                        border: '1px solid var(--color-success)',
                        color: 'var(--color-success)',
                        cursor: 'pointer',
                        flexShrink: 0,
                      }}
                      onMouseEnter={e => {
                        e.currentTarget.style.backgroundColor = 'var(--color-success)';
                        e.currentTarget.style.color = '#000';
                      }}
                      onMouseLeave={e => {
                        e.currentTarget.style.backgroundColor = 'transparent';
                        e.currentTarget.style.color = 'var(--color-success)';
                      }}
                    >
                      Run
                    </button>
                  </div>
                </div>
              ))}

              {/* Empty state — no issues at all */}
              {agentRunCards.length === 0 && idleIssueCards.length === 0 && displayedProjects.map(project => (
                <div
                  key={`empty-${project.id}`}
                  style={{
                    backgroundColor: 'var(--color-bg-card)',
                    border: '1px solid var(--color-border)',
                    borderLeft: '3px solid var(--color-text-secondary)',
                  }}
                >
                  <div style={{
                    display: 'flex',
                    alignItems: 'center',
                    padding: '12px',
                    gap: '12px',
                  }}>
                    <span style={{
                      width: '8px',
                      height: '8px',
                      borderRadius: '50%',
                      backgroundColor: 'var(--color-text-secondary)',
                      flexShrink: 0,
                    }} />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{
                        fontSize: '13px',
                        fontWeight: 600,
                      }}>
                        {project.name}
                      </div>
                      <div style={{
                        fontSize: '11px',
                        color: 'var(--color-text-secondary)',
                        marginTop: '2px',
                      }}>
                        No issues yet
                      </div>
                    </div>
                    <button
                      onClick={() => {
                        setNewIssueProjectId(project.id);
                        setShowNewIssueModal(true);
                      }}
                      style={{
                        padding: '4px 10px',
                        fontSize: '11px',
                        fontFamily: 'inherit',
                        background: 'transparent',
                        border: '1px solid var(--color-border)',
                        color: 'var(--color-success)',
                        cursor: 'pointer',
                        flexShrink: 0,
                      }}
                      onMouseEnter={e => (e.currentTarget.style.backgroundColor = 'var(--color-bg-card-hover)')}
                      onMouseLeave={e => (e.currentTarget.style.backgroundColor = 'transparent')}
                    >
                      + Issue
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Bottom event log */}
      <EventLog entries={eventLog} />

      {/* Floating action button */}
      <FloatingActionButton
        onNewIssue={handleNewIssue}
        onNewProject={handleNewProject}
        onSyncGithub={handleSyncGithub}
      />

      {/* New Issue Modal */}
      {showNewIssueModal && (
        <NewIssueModal
          projects={projects}
          defaultProjectId={newIssueProjectId}
          onSubmit={handleIssueSubmit}
          onClose={() => { setShowNewIssueModal(false); setNewIssueProjectId(null); }}
        />
      )}

      {/* Delete Confirmation Dialog */}
      {deleteConfirm && (
        <ConfirmDialog
          title="Delete project"
          message={`Delete "${deleteConfirm.name}"? This will remove all its issues and pipeline runs.`}
          confirmLabel="Delete"
          onConfirm={() => {
            handleDeleteProject(deleteConfirm.id);
            setDeleteConfirm(null);
          }}
          onCancel={() => setDeleteConfirm(null)}
        />
      )}

      {/* Project Setup Modal */}
      {showProjectSetup && (
        <div
          data-testid="project-setup-modal"
          onClick={() => setShowProjectSetup(false)}
          style={{
            position: 'fixed',
            inset: 0,
            backgroundColor: 'rgba(0,0,0,0.7)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 100,
          }}
        >
          <div onClick={e => e.stopPropagation()} style={{ width: '100%', maxWidth: '500px' }}>
            <ProjectSetup
              projects={projects}
              onSelect={handleProjectSelect}
              onCreate={handleProjectCreate}
              onClone={handleCloneProject}
            />
          </div>
        </div>
      )}
    </div>
  );
}

function App() {
  const wsUrl = `${window.location.protocol === 'https:' ? 'wss:' : 'ws:'}//${window.location.host}/ws`;
  return (
    <WebSocketProvider url={wsUrl}>
      <MissionControl />
    </WebSocketProvider>
  );
}

export default App;

